		SET @Proc_Step_Name = ' UPDATE TABLE  CODED_TABLE_INV_ADMINISTRATIVE';
		UPDATE rdb.dbo.CODED_TABLE_INV_ADMINISTRATIVE
		  SET ANSWER_TXT1 = ANSWER_TXT
		WHERE RTRIM(ANSWER_TXT1) = '';
		IF OBJECT_ID('rdb.dbo.CODED_TABLE_DESC_INV_ADMINISTRATIVE_TEMP', 'U') IS NOT NULL
		BEGIN
			DROP TABLE rdb.dbo.CODED_TABLE_DESC_INV_ADMINISTRATIVE_TEMP;
		END;

		SELECT p1.PAGE_CASE_UID, p1.NBS_QUESTION_UID, STUFF(
		(
			SELECT TOP 10 ' | ' + ANSWER_TXT1
			FROM [RDB].[dbo].[CODED_TABLE_INV_ADMINISTRATIVE] AS p2
			WHERE p2.PAGE_CASE_UID = p1.PAGE_CASE_UID AND 
				  p2.nbs_question_uid = p1.NBS_QUESTION_UID
			ORDER BY PAGE_CASE_UID, NBS_QUESTION_UID, NBS_CASE_ANSWER_UID FOR XML PATH(''), TYPE
		).value( '.', 'varchar(2000)' ), 1, 3, '') AS ANSWER_DESC11
		INTO [RDB].[dbo].[CODED_TABLE_DESC_INV_ADMINISTRATIVE_TEMP]
		FROM [RDB].[dbo].[CODED_TABLE_INV_ADMINISTRATIVE] AS p1
		--where  nbs_question_uid is not null
		GROUP BY PAGE_CASE_UID, RDB_COLUMN_NM, NBS_QUESTION_UID;
		IF OBJECT_ID('rdb.dbo.CODED_TABLE_DESC_INV_ADMINISTRATIVE', 'U') IS NOT NULL
		BEGIN
			DROP TABLE rdb.dbo.CODED_TABLE_DESC_INV_ADMINISTRATIVE;
		END;

		SELECT ct.*, COALESCE(ctt.answer_desc11, ct.answer_txt1) AS answer_desc11
		INTO rdb.dbo.CODED_TABLE_DESC_INV_ADMINISTRATIVE
		FROM [RDB].[dbo].[CODED_TABLE_INV_ADMINISTRATIVE] AS ct LEFT
			 OUTER JOIN
			 [CODED_TABLE_DESC_INV_ADMINISTRATIVE_TEMP] AS ctt
			 ON ct.PAGE_CASE_UID = ctt.PAGE_CASE_UID AND 
				ct.NBS_QUESTION_UID = ctt.NBS_QUESTION_UID;
		SELECT @RowCount_no = @@ROWCOUNT;
		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_ADMINISTRATIVE', 'RDB.S_INV_ADMINISTRATIVE', 'START', @Proc_Step_no, @Proc_Step_Name, @RowCount_no );

		COMMIT TRANSACTION;

		BEGIN TRANSACTION;
		SET @Proc_Step_no = 26;
		SET @Proc_Step_Name = 'CREATE TABLE  CODED_COUNTY_TABLE_INV_ADMINISTRATIVE'; 
		--CREATE TABLE 	CODED_COUNTY_TABLE 
		IF OBJECT_ID('rdb.dbo.CODED_COUNTY_TABLE_INV_ADMINISTRATIVE', 'U') IS NOT NULL
		BEGIN
			DROP TABLE rdb.dbo.CODED_COUNTY_TABLE_INV_ADMINISTRATIVE;
		END;

		SELECT CODED.CODE_SET_GROUP_ID, PAGE_CASE_UID, NBS_QUESTION_UID, NBS_CASE_ANSWER_UID, ANSWER_TXT, CVG.CODE_SET_NM, RDB_COLUMN_NM, ANSWER_OTH, CVG.CODE, CODE_SHORT_DESC_TXT AS 'ANSWER_TXT1'
		INTO rdb.dbo.CODED_COUNTY_TABLE_INV_ADMINISTRATIVE
		FROM rdb.dbo.CODED_TABLE_INV_ADMINISTRATIVE AS CODED WITH(NOLOCK) LEFT
			 JOIN
			 NBS_SRTE.dbo.CODESET_GROUP_METADATA AS METADATA WITH(NOLOCK)
			 ON METADATA.CODE_SET_GROUP_ID = CODED.CODE_SET_GROUP_ID LEFT
																		  JOIN
																		  NBS_SRTE.dbo.V_STATE_COUNTY_CODE_VALUE AS CVG WITH(NOLOCK)
																		  ON CVG.CODE_SET_NM = METADATA.CODE_SET_NM AND 
																			 CVG.CODE = CODED.ANSWER_TXT
		WHERE METADATA.CODE_SET_NM = 'COUNTY_CCD';
		IF OBJECT_ID('rdb.dbo.CODED_COUNTY_TABLE_DESC_INV_ADMINISTRATIVE_TEMP', 'U') IS NOT NULL
		BEGIN
			DROP TABLE rdb.dbo.CODED_COUNTY_TABLE_DESC_INV_ADMINISTRATIVE_TEMP;
		END;

		SELECT p1.PAGE_CASE_UID, p1.NBS_QUESTION_UID, STUFF(
		(
			SELECT TOP 10 ' |' + ANSWER_TXT1
			FROM [RDB].[dbo].[CODED_COUNTY_TABLE_INV_ADMINISTRATIVE] AS p2
			WHERE p2.PAGE_CASE_UID = p1.PAGE_CASE_UID AND 
				  p2.nbs_question_uid = p1.NBS_QUESTION_UID
			ORDER BY PAGE_CASE_UID, NBS_QUESTION_UID, NBS_CASE_ANSWER_UID FOR XML PATH(''), TYPE
		).value( '.', 'varchar(2000)' ), 1, 2, '') AS ANSWER_DESC11
		INTO [RDB].[dbo].[CODED_COUNTY_TABLE_DESC_INV_ADMINISTRATIVE_TEMP]
		FROM [RDB].[dbo].[CODED_COUNTY_TABLE_INV_ADMINISTRATIVE] AS p1
		GROUP BY PAGE_CASE_UID, NBS_QUESTION_UID;
		IF OBJECT_ID('rdb.dbo.CODED_COUNTY_TABLE_DESC_INV_ADMINISTRATIVE', 'U') IS NOT NULL
		BEGIN
			DROP TABLE rdb.dbo.CODED_COUNTY_TABLE_DESC_INV_ADMINISTRATIVE;
		END;

		SELECT cct.*, cctt.answer_desc11
