		SELECT @RowCount_no = @@ROWCOUNT;
		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_ADMINISTRATIVE', 'RDB.S_INV_ADMINISTRATIVE', 'START', @Proc_Step_no, @Proc_Step_Name, @RowCount_no );

		COMMIT TRANSACTION;

		BEGIN TRANSACTION;
		SET @Proc_Step_no = 36;
		SET @Proc_Step_Name = ' CREATE TABLE PAGE_DATE_TABLE_INV_ADMINISTRATIVE';
		IF OBJECT_ID('rdb.dbo.PAGE_DATE_TABLE_INV_ADMINISTRATIVE', 'U') IS NOT NULL
		BEGIN
			DROP TABLE RDB.dbo.PAGE_DATE_TABLE_INV_ADMINISTRATIVE;
		END;
		CREATE TABLE RDB.dbo.PAGE_DATE_TABLE_INV_ADMINISTRATIVE
		( 
					 NBS_CASE_ANSWER_UID bigint, CODE_SET_GROUP_ID bigint, RDB_COLUMN_NM char(40), ANSWER_TXT1 date, PAGE_CASE_UID bigint, LAST_CHG_TIME date, RECORD_STATUS_CD char(40)
		);
 
		--IF PAGE_CASE_UID=. THEN PAGE_CASE_UID= 1;
		UPDATE rdb.dbo.DATE_DATA_INV_ADMINISTRATIVE
		  SET PAGE_CASE_UID = 1
