		SELECT @RowCount_no = @@ROWCOUNT;
		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_ADMINISTRATIVE', 'RDB.S_INV_ADMINISTRATIVE', 'START', @Proc_Step_no, @Proc_Step_Name, @RowCount_no );

		COMMIT TRANSACTION;

		BEGIN TRANSACTION;
		SET @Proc_Step_no = 37;
		SET @Proc_Step_Name = ' UPDATE TABLE  PAGE_DATE_TABLE_INV_ADMINISTRATIVE'; 
		--%DBLOAD (PAGE_DATE_TABLE, DATE_DATA); 
		INSERT INTO rdb.dbo.PAGE_DATE_TABLE_INV_ADMINISTRATIVE( NBS_CASE_ANSWER_UID, CODE_SET_GROUP_ID, RDB_COLUMN_NM, ANSWER_TXT1, PAGE_CASE_UID, RECORD_STATUS_CD )
			   SELECT NBS_CASE_ANSWER_UID, CODE_SET_GROUP_ID, RDB_COLUMN_NM, CAST(ANSWER_TXT1 AS datetime), PAGE_CASE_UID, 
			   --	LAST_CHG_TIME , 
			   RECORD_STATUS_CD
			   FROM rdb.dbo.DATE_DATA_INV_ADMINISTRATIVE;
		SELECT @RowCount_no = @@ROWCOUNT;
		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_ADMINISTRATIVE', 'RDB.S_INV_ADMINISTRATIVE', 'START', @Proc_Step_no, @Proc_Step_Name, @RowCount_no );

		COMMIT TRANSACTION;

		BEGIN TRANSACTION;
		SET @Proc_Step_no = 39;
		SET @Proc_Step_Name = ' UPDATE TABLE  PAGE_DATE_TABLE_INV_ADMINISTRATIVE';
		IF OBJECT_ID('rdb.dbo.date_data_INV_ADMINISTRATIVE_out', 'U') IS NOT NULL
		BEGIN
			DROP TABLE rdb.dbo.date_data_INV_ADMINISTRATIVE_out;
		END;
		SET @columns = N'';
		SELECT @columns+=N', p.' + QUOTENAME(LTRIM(RTRIM([RDB_COLUMN_NM])))
		FROM
		(
			SELECT [RDB_COLUMN_NM]
			FROM [dbo].PAGE_DATE_TABLE_INV_ADMINISTRATIVE AS p
			GROUP BY [RDB_COLUMN_NM]
		) AS x;
		SET @sql = N'
SELECT [PAGE_CASE_UID] as PAGE_CASE_UID_date, ' + STUFF(@columns, 1, 2, '') + ' into rdb.dbo.DATE_DATA_INV_ADMINISTRATIVE_out ' + 'FROM (
SELECT [PAGE_CASE_UID], [answer_txt1] , [RDB_COLUMN_NM] 
 FROM rdb.[dbo].PAGE_DATE_TABLE_INV_ADMINISTRATIVE
	group by [PAGE_CASE_UID], [answer_txt1] , [RDB_COLUMN_NM] 
		) AS j PIVOT (max(answer_txt1) FOR [RDB_COLUMN_NM] in 
	   (' + STUFF(REPLACE(@columns, ', p.[', ',['), 1, 1, '') + ')) AS p;';
		PRINT @sql;
		EXEC sp_executesql @sql;
		--select * from rdb.dbo.DATE_DATA_INV_ADMINISTRATIVE_out;
		SELECT @RowCount_no = @@ROWCOUNT;
		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_ADMINISTRATIVE', 'RDB.S_INV_ADMINISTRATIVE', 'START', @Proc_Step_no, @Proc_Step_Name, @RowCount_no );

