		SELECT sk.*, ndo.*, ddo.*, cdo.*, tdo.*
		INTO rdb.dbo.S_INV_CONTACT
		FROM rdb.dbo.STAGING_KEY_INV_CONTACT_FINAL AS sk LEFT
			 OUTER JOIN
