															 OUTER JOIN
															 rdb.dbo.CODED_DATA_INV_CONTACT_out AS cdo
															 ON cdo.PAGE_CASE_UID_coded = sk.PAGE_CASE_UID LEFT
																									  OUTER JOIN
																									  rdb.dbo.text_data_INV_CONTACT_OUT AS tdo
																									  ON tdo.PAGE_CASE_UID_text = sk.PAGE_CASE_UID;
