			SELECT [RDB_COLUMN_NM]
			FROM [dbo].PAGE_DATE_TABLE_INV_EPIDEMIOLOGY AS p
			GROUP BY [RDB_COLUMN_NM]
		) AS x;
		SET @sql = N'
SELECT [PAGE_CASE_UID] as PAGE_CASE_UID_date, ' + STUFF(@columns, 1, 2, '') + ' into rdb.dbo.DATE_DATA_INV_EPIDEMIOLOGY_out ' + 'FROM (
SELECT [PAGE_CASE_UID], [answer_txt1] , [RDB_COLUMN_NM] 
 FROM rdb.[dbo].PAGE_DATE_TABLE_INV_EPIDEMIOLOGY
	group by [PAGE_CASE_UID], [answer_txt1] , [RDB_COLUMN_NM] 
		) AS j PIVOT (max(answer_txt1) FOR [RDB_COLUMN_NM] in 
	   (' + STUFF(REPLACE(@columns, ', p.[', ',['), 1, 1, '') + ')) AS p;';
		PRINT @sql;
