		BEGIN TRANSACTION;
		SET @Proc_Step_no = 44;
		SET @Proc_Step_Name = ' CREATE TABLE  NUMERIC_DATA_MERGED_INV_EPIDEMIOLOGY';
		IF OBJECT_ID('rdb.dbo.NUMERIC_DATA_MERGED_INV_EPIDEMIOLOGY', 'U') IS NOT NULL
		BEGIN
			DROP TABLE rdb.dbo.NUMERIC_DATA_MERGED_INV_EPIDEMIOLOGY;
		END;

		SELECT COALESCE(nbd.NBS_CASE_ANSWER_UID, nd2.NBS_CASE_ANSWER_UID) AS NBS_CASE_ANSWER_UID, COALESCE(nbd.[RDB_COLUMN_NM2], nd2.[RDB_COLUMN_NM2]) AS [RDB_COLUMN_NM2], COALESCE(nbd.[CODE_SET_GROUP_ID], nd2.[CODE_SET_GROUP_ID]) AS [CODE_SET_GROUP_ID], COALESCE(nbd.[RDB_COLUMN_NM], nd2.[RDB_COLUMN_NM]) AS [RDB_COLUMN_NM], COALESCE(nbd.[ANSWER_TXT], nd2.[ANSWER_TXT]) AS [ANSWER_TXT], COALESCE(nbd.[PAGE_CASE_UID], nd2.[PAGE_CASE_UID]) AS [PAGE_CASE_UID], COALESCE(nbd.[RECORD_STATUS_CD], nd2.[RECORD_STATUS_CD]) AS [RECORD_STATUS_CD], COALESCE(nbd.[NBS_QUESTION_UID], nd2.[NBS_QUESTION_UID]) AS [NBS_QUESTION_UID], COALESCE(nbd.[TXT_LEN], nd2.[TXT_LEN]) AS [TXT_LEN], COALESCE(nbd.[ANSWER_UNIT], nd2.[ANSWER_UNIT]) AS [ANSWER_UNIT], COALESCE(nbd.[LENCODED], nd2.[LENCODED]) AS [LENCODED], COALESCE(nbd.[ANSWER_CODED], nd2.[ANSWER_CODED]) AS [ANSWER_CODED], COALESCE(nbd.[UNIT_VALUE1], nd2.[UNIT_VALUE1]) AS [UNIT_VALUE1]
		INTO rdb.dbo.NUMERIC_DATA_MERGED_INV_EPIDEMIOLOGY
		FROM [RDB].[dbo].NUMERIC_BASE_DATA_INV_EPIDEMIOLOGY AS nbd
			 FULL OUTER JOIN
			 [RDB].[dbo].NUMERIC_DATA_2_INV_EPIDEMIOLOGY AS nd2
			 ON nbd.NBS_CASE_ANSWER_UID = nd2.NBS_CASE_ANSWER_UID AND 
				nbd.[RDB_COLUMN_NM] = nd2.[RDB_COLUMN_NM];
		SELECT @RowCount_no = @@ROWCOUNT;
		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_EPIDEMIOLOGY', 'RDB.S_INV_EPIDEMIOLOGY', 'START', @Proc_Step_no, @Proc_Step_Name, @RowCount_no );

		COMMIT TRANSACTION;

		BEGIN TRANSACTION;
		SET @Proc_Step_no = 45;
		SET @Proc_Step_Name = ' CREATE TABLE  NUMERIC_DATA_TRANS_INV_EPIDEMIOLOGY'; 
		--CREATE TABLE 	NUMERIC_DATA_TRANS  AS 
		IF OBJECT_ID('rdb.dbo.NUMERIC_DATA_TRANS_INV_EPIDEMIOLOGY', 'U') IS NOT NULL
		BEGIN
			DROP TABLE rdb.dbo.NUMERIC_DATA_TRANS_INV_EPIDEMIOLOGY;
		END;

		SELECT PAGE_CASE_UID, NBS_QUESTION_UID, NBS_CASE_ANSWER_UID, ANSWER_UNIT, ANSWER_CODED, CVG.CODE_SET_NM, RDB_COLUMN_NM, ANSWER_TXT, CODE, CODE_SHORT_DESC_TXT AS UNIT, CAST(NULL AS [varchar](2000)) AS ANSWER_TXT_F
		INTO rdb.dbo.NUMERIC_DATA_TRANS_INV_EPIDEMIOLOGY
		FROM rdb.dbo.NUMERIC_DATA_MERGED_INV_EPIDEMIOLOGY AS CODED WITH(NOLOCK) LEFT
			 JOIN
			 NBS_SRTE.dbo.CODESET_GROUP_METADATA AS METADATA WITH(NOLOCK)
			 ON METADATA.CODE_SET_GROUP_ID = CODED.CODE_SET_GROUP_ID LEFT
																				JOIN
																				NBS_SRTE.dbo.CODE_VALUE_GENERAL AS CVG WITH(NOLOCK)
																				ON CVG.CODE_SET_NM = METADATA.CODE_SET_NM
		WHERE CVG.CODE = CODED.ANSWER_CODED OR 
			  ANSWER_CODED IS NULL
		ORDER BY PAGE_CASE_UID;
		UPDATE rdb.dbo.NUMERIC_DATA_TRANS_INV_EPIDEMIOLOGY
		  SET PAGE_CASE_UID = COALESCE(PAGE_CASE_UID, 1), ANSWER_TXT_F = CASE
																		 WHEN COALESCE(RTRIM(UNIT), '') = '' THEN ANSWER_TXT
																		 WHEN CHARINDEX(' UNIT', RDB_COLUMN_NM) > 0 THEN UNIT
																		 ELSE ANSWER_UNIT
																		 END;

		SELECT @RowCount_no = @@ROWCOUNT;
		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_EPIDEMIOLOGY', 'RDB.S_INV_EPIDEMIOLOGY', 'START', @Proc_Step_no, @Proc_Step_Name, @RowCount_no );


		COMMIT TRANSACTION;

		BEGIN TRANSACTION;
		SET @Proc_Step_no = 48;
		SET @Proc_Step_Name = ' UPDATE TABLE  CODED_TABLE_SNTEMP_TRANS_A_INV_EPIDEMIOLOGY'; 
		--CREATE TABLE NUMERIC_DATA_TRANS1_INV_EPIDEMIOLOGY AS 
		IF OBJECT_ID('rdb.dbo.NUMERIC_DATA_TRANS1_INV_EPIDEMIOLOGY', 'U') IS NOT NULL
		BEGIN
			DROP TABLE rdb.dbo.NUMERIC_DATA_TRANS1_INV_EPIDEMIOLOGY;
		END;
		IF OBJECT_ID('rdb.dbo.CODED_TABLE_MERGED_INV_EPIDEMIOLOGY', 'U') IS NULL
		BEGIN
			CREATE TABLE [dbo].CODED_TABLE_MERGED_INV_EPIDEMIOLOGY
			( 
						 [RDB_COLUMN_NM] [varchar](30) NULL, [ANSWER_TXT] [varchar](2000) NULL
			)
			ON [PRIMARY];
		END;

		SELECT DISTINCT 
			   ndtis.PAGE_CASE_UID, ndtis.RDB_COLUMN_NM, ANSWER_UNIT, ANSWER_TXT_F AS ANSWER_TXT
		INTO rdb.dbo.NUMERIC_DATA_TRANS1_INV_EPIDEMIOLOGY
		FROM rdb.dbo.NUMERIC_DATA_TRANS_INV_EPIDEMIOLOGY AS ndtis LEFT
			 OUTER JOIN
			 rdb.dbo.CODED_TABLE_MERGED_INV_EPIDEMIOLOGY AS ctmis
			 ON ndtis.RDB_COLUMN_NM = ctmis.RDB_COLUMN_NM AND 
				ctmis.answer_txt IS NOT NULL AND 
				ctmis.RDB_COLUMN_NM IS NULL;


		COMMIT TRANSACTION;

		BEGIN TRANSACTION;
		WITH lst
			 AS (SELECT ndtis.rdb_column_nm,
							  CASE
							  WHEN ndtis.answer_txt IS NOT NULL THEN 1
							  ELSE 0
							  END AS Ans_null
				 FROM rdb.[dbo].[NUMERIC_DATA_TRANS1_INV_EPIDEMIOLOGY] AS ndtis LEFT
					  OUTER JOIN
					  rdb.dbo.CODED_TABLE_MERGED_INV_EPIDEMIOLOGY AS ctmis
					  ON ndtis.RDB_COLUMN_NM = ctmis.RDB_COLUMN_NM AND 
						 ctmis.answer_txt IS NOT NULL AND 
						 ctmis.RDB_COLUMN_NM IS NULL)
			 DELETE FROM rdb.dbo.CODED_TABLE_MERGED_INV_EPIDEMIOLOGY
			 WHERE RDB_COLUMN_NM IN
			 (
				 SELECT rdb_column_nm
				 FROM lst
				 WHERE ans_null != 0
			 );

		COMMIT TRANSACTION;

		BEGIN TRANSACTION;
		WITH lst
			 AS (SELECT rdb_column_nm,
						CASE
						WHEN answer_txt IS NOT NULL THEN 1
						ELSE 0
						END AS Ans_null
				 FROM rdb.[dbo].[NUMERIC_DATA_TRANS1_INV_EPIDEMIOLOGY]
				 WHERE RDB_COLUMN_NM IN
				 (
					 SELECT RDB_COLUMN_NM
					 FROM rdb.dbo.CODED_TABLE_MERGED_INV_EPIDEMIOLOGY
					 GROUP BY rdb_column_nm
				 )
				 GROUP BY rdb_column_nm,
						  CASE
						  WHEN answer_txt IS NOT NULL THEN 1
						  ELSE 0
						  END)
			 DELETE FROM rdb.[dbo].[NUMERIC_DATA_TRANS1_INV_EPIDEMIOLOGY]
			 WHERE rdb_column_nm IN
			 (
				 SELECT rdb_column_nm
				 FROM lst
				 WHERE ans_null = 0
				 EXCEPT
				 SELECT rdb_column_nm
				 FROM lst
				 WHERE ans_null = 1
			 );
		COMMIT TRANSACTION;

		BEGIN TRANSACTION;
		SET @Proc_Step_no = 49;
		SET @Proc_Step_Name = ' CREATE TABLE  CODED_DATA_INV_EPIDEMIOLOGY_out';
		IF OBJECT_ID('rdb.dbo.CODED_DATA_INV_EPIDEMIOLOGY_out', 'U') IS NOT NULL
		BEGIN
			DROP TABLE rdb.dbo.CODED_DATA_INV_EPIDEMIOLOGY_out;
		END;
		IF OBJECT_ID('rdb.dbo.CODED_TABLE_MERGED_INV_EPIDEMIOLOGY', 'U') IS NOT NULL
		BEGIN
			UPDATE rdb.[dbo].CODED_TABLE_MERGED_INV_EPIDEMIOLOGY
			  SET answer_desc11 = NULL
			WHERE answer_desc11 = '';
		END;

		IF OBJECT_ID('rdb.dbo.CODED_TABLE_MERGED_INV_EPIDEMIOLOGY', 'U') IS NOT NULL
		BEGIN
			UPDATE rdb.[dbo].CODED_TABLE_MERGED_INV_EPIDEMIOLOGY
			  SET answer_desc11 = ANSWER_VALUE
			WHERE ANSWER_OTH IS NOT NULL AND 
				  ANSWER_VALUE IS NOT NULL AND 
				  answer_desc11 IS NULL AND 
				  answer_oth IS NOT NULL;
		END;

		IF OBJECT_ID('rdb.dbo.CODED_TABLE_MERGED_INV_EPIDEMIOLOGY', 'U') IS NOT NULL
		BEGIN
			UPDATE rdb.[dbo].CODED_TABLE_MERGED_INV_EPIDEMIOLOGY
			  SET answer_desc11 = ANSWER_TXT
			WHERE ANSWER_OTH IS NULL AND 
				  ANSWER_TXT2 IS NOT NULL AND 
				  ( answer_desc11 IS NULL
				  ) AND 
				  answer_oth IS NULL AND 
				  LEN(ANSWER_TXT2) > 0;
		END;

		IF OBJECT_ID('rdb.dbo.CODED_TABLE_MERGED_INV_EPIDEMIOLOGY', 'U') IS NOT NULL
		BEGIN
			UPDATE rdb.[dbo].CODED_TABLE_MERGED_INV_EPIDEMIOLOGY
			  SET answer_desc11 = ANSWER_TXT
			WHERE ANSWER_OTH IS NULL AND 
				  ANSWER_TXT2 IS NOT NULL AND 
				  ( answer_desc11 IS NULL
				  ) AND 
				  answer_oth IS NULL AND 
				  LEN(ANSWER_TXT) > 0;
		END;



		IF OBJECT_ID('rdb.dbo.CODED_TABLE_MERGED_INV_EPIDEMIOLOGY', 'U') IS NOT NULL
		BEGIN
			UPDATE rdb.[dbo].CODED_TABLE_MERGED_INV_EPIDEMIOLOGY
			  SET answer_desc11 = ANSWER_VALUE
			WHERE ANSWER_OTH IS NULL AND 
				  ANSWER_VALUE IS NOT NULL AND 
				  answer_desc11 IS NULL AND 
				  answer_txt IS NOT NULL AND 
				  code = '';
		END;

		IF OBJECT_ID('rdb.dbo.CODED_TABLE_MERGED_INV_EPIDEMIOLOGY', 'U') IS NOT NULL
		BEGIN
			UPDATE rdb.[dbo].CODED_TABLE_MERGED_INV_EPIDEMIOLOGY
			  SET answer_desc11 = ANSWER_TXT
			WHERE answer_desc11 IS NULL AND 
				  ANSWER_OTH IS NULL AND 
				  ANSWER_TXT2 IS NULL AND 
				  answer_oth IS NULL AND 
				  ANSWER_TXT IS NOT NULL AND 
				  ANSWER_TXT <> ''
		END;

		SET @columns = N'';
		SELECT @columns+=N', p.' + QUOTENAME(LTRIM(RTRIM([RDB_COLUMN_NM])))
		FROM
		(
			SELECT [RDB_COLUMN_NM]
			FROM [dbo].CODED_TABLE_MERGED_INV_EPIDEMIOLOGY AS p
			GROUP BY [RDB_COLUMN_NM]
		) AS x;
		SET @sql = N'
SELECT [PAGE_CASE_UID] as PAGE_CASE_UID_coded, ' + STUFF(@columns, 1, 2, '') + ' into rdb.dbo.CODED_DATA_INV_EPIDEMIOLOGY_out ' + 'FROM (
SELECT [PAGE_CASE_UID], [ANSWER_DESC11] , [RDB_COLUMN_NM] 
 FROM rdb.[dbo].CODED_TABLE_MERGED_INV_EPIDEMIOLOGY
	group by [PAGE_CASE_UID], [ANSWER_DESC11] , [RDB_COLUMN_NM] 
		) AS j PIVOT (max(ANSWER_DESC11) FOR [RDB_COLUMN_NM] in 
	   (' + STUFF(REPLACE(@columns, ', p.[', ',['), 1, 1, '') + ')) AS p;';
		PRINT @sql;
		EXEC sp_executesql @sql;
		SELECT @RowCount_no = @@ROWCOUNT;
		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_EPIDEMIOLOGY', 'RDB.S_INV_EPIDEMIOLOGY', 'START', @Proc_Step_no, @Proc_Step_Name, @RowCount_no );

		COMMIT TRANSACTION;
		BEGIN TRANSACTION;
		SET @Proc_Step_no = 49;
		SET @Proc_Step_Name = ' LOG Invalid Numeric data INTO ETL_DQ_LOG';
	
		INSERT INTO rdb.dbo.ETL_DQ_LOG( EVENT_TYPE, EVENT_LOCAL_ID, EVENT_UID, DQ_ISSUE_CD, DQ_ISSUE_DESC_TXT, DQ_ISSUE_QUESTION_IDENTIFIER, DQ_ISSUE_ANSWER_TXT, DQ_ISSUE_RDB_LOCATION, JOB_BATCH_LOG_UID, DQ_ETL_PROCESS_TABLE, DQ_ETL_PROCESS_COLUMN, DQ_STATUS_TIME, DQ_ISSUE_SOURCE_LOCATION, DQ_ISSUE_SOURCE_QUESTION_LABEL )
		(
		SELECT DISTINCT 'INVESTIGATION', PUBLIC_HEALTH_CASE.LOCAL_ID, PUBLIC_HEALTH_CASE_UID, 
		'INVALID_NUMERIC_VALUE', 'BAD NUMERIC VALUE: A non-numeric value exists in a field expecting a numeric value and requires update. Please correct the bad numeric value so that it can be properly written to the reporting database during the next ETL run', 
		NBS_UI_METADATA.QUESTION_IDENTIFIER, ANSWER_TXT, NBS_UI_METADATA.DATA_LOCATION, @Batch_id, NBS_RDB_METADATA.rdb_table_nm, NBS_RDB_METADATA.RDB_COLUMN_NM, 
		GETDATE(), NBS_UI_METADATA.DATA_LOCATION, QUESTION_LABEL
					FROM rdb.dbo.NUMERIC_DATA_TRANS1_INV_EPIDEMIOLOGY
			 INNER JOIN
				 NBS_ODSE.DBO.PUBLIC_HEALTH_CASE
				 ON NUMERIC_DATA_TRANS1_INV_EPIDEMIOLOGY.page_case_uid= PUBLIC_HEALTH_CASE.PUBLIC_HEALTH_CASE_UID
				 INNER JOIN
				 NBS_SRTE.DBO.CONDITION_CODE
				 ON CONDITION_CODE.CONDITION_CD = PUBLIC_HEALTH_CASE.CD
				  INNER JOIN
				 NBS_ODSE.DBO.NBS_RDB_METADATA
				 ON NBS_RDB_METADATA.rdb_column_nm = NUMERIC_DATA_TRANS1_INV_EPIDEMIOLOGY.rdb_column_nm
				 INNER JOIN
				 NBS_ODSE.DBO.NBS_UI_METADATA
				 ON NBS_RDB_METADATA.NBS_UI_METADATA_UID = NBS_UI_METADATA.NBS_UI_METADATA_UID AND 
					CONDITION_CODE.INVESTIGATION_FORM_CD = NBS_UI_METADATA.INVESTIGATION_FORM_CD
			WHERE (isNumeric(ANSWER_TXT) != 1) AND 
				  ANSWER_TXT IS NOT NULL);
		
		SELECT @RowCount_no = @@ROWCOUNT;
		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_EPIDEMIOLOGY', 'RDB.S_INV_EPIDEMIOLOGY', 'START', @Proc_Step_no, @Proc_Step_Name, @RowCount_no );


		COMMIT TRANSACTION;

		BEGIN TRANSACTION;
		SET @Proc_Step_no = 50;
		SET @Proc_Step_Name = ' CREATE TABLE  NUMERIC_DATA_PIVOT_INV_EPIDEMIOLOGY';
		IF OBJECT_ID('rdb.dbo.NUMERIC_DATA_PIVOT_INV_EPIDEMIOLOGY', 'U') IS NOT NULL
		BEGIN
			DROP TABLE rdb.dbo.NUMERIC_DATA_PIVOT_INV_EPIDEMIOLOGY;
		END;
		SET @columns = N'';
		SELECT @columns+=N', p.' + QUOTENAME(LTRIM(RTRIM([RDB_COLUMN_NM])))
		FROM
		(
			SELECT [RDB_COLUMN_NM]
			FROM [dbo].NUMERIC_DATA_TRANS1_INV_EPIDEMIOLOGY AS p
			GROUP BY [RDB_COLUMN_NM]
		) AS x;
		SET @sql = N'
SELECT [PAGE_CASE_UID] as PAGE_CASE_UID_NUMERIC, ' + STUFF(@columns, 1, 2, '') + ' into rdb.dbo.NUMERIC_DATA_PIVOT_INV_EPIDEMIOLOGY ' + 'FROM (
SELECT [PAGE_CASE_UID], [answer_txt] , [RDB_COLUMN_NM] 
 FROM rdb.[dbo].NUMERIC_DATA_TRANS1_INV_EPIDEMIOLOGY 
 WHERE (isNumeric(ANSWER_TXT) = 1) AND  ANSWER_TXT IS NOT NULL 
	group by [PAGE_CASE_UID], [answer_txt] , [RDB_COLUMN_NM] 
		) AS j PIVOT (max(answer_txt) FOR [RDB_COLUMN_NM] in 
	   (' + STUFF(REPLACE(@columns, ', p.[', ',['), 1, 1, '') + ')) AS p;';
		PRINT @sql;
		EXEC sp_executesql @sql;
		SELECT @RowCount_no = @@ROWCOUNT;
		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_EPIDEMIOLOGY', 'RDB.S_INV_EPIDEMIOLOGY', 'START', @Proc_Step_no, @Proc_Step_Name, @RowCount_no );


		COMMIT TRANSACTION;


		BEGIN TRANSACTION;
		SET @Proc_Step_no = 51;
		SET @Proc_Step_Name = ' CREATE TABLE NUMERIC_DATA_OUT_INV_EPIDEMIOLOGY';
		IF OBJECT_ID('rdb.dbo.NUMERIC_DATA_OUT_INV_EPIDEMIOLOGY', 'U') IS NOT NULL
		BEGIN
			DROP TABLE rdb.dbo.NUMERIC_DATA_OUT_INV_EPIDEMIOLOGY;
		END;
		--CREATE TABLE NUMERIC_DATA_OUT 
		IF OBJECT_ID('rdb.dbo.NUMERIC_DATA_PIVOT_INV_EPIDEMIOLOGY', 'U') IS NOT NULL
		BEGIN
			SELECT *
			INTO rdb.dbo.NUMERIC_DATA_OUT_INV_EPIDEMIOLOGY
			FROM rdb.dbo.NUMERIC_DATA_PIVOT_INV_EPIDEMIOLOGY
			WHERE 
			---??? LEN(RTRIM(_LABEL_))>0    AND 
			PAGE_CASE_UID_NUMERIC > 0;
		END;
		---************************************************
		SELECT @RowCount_no = @@ROWCOUNT;
		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_EPIDEMIOLOGY', 'RDB.S_INV_EPIDEMIOLOGY', 'START', @Proc_Step_no, @Proc_Step_Name, @RowCount_no );

		COMMIT TRANSACTION;

		BEGIN TRANSACTION;
		SET @Proc_Step_no = 52;
		SET @Proc_Step_Name = ' Generating Stageing_key_metadata_INV_EPIDEMIOLOGY';
		IF OBJECT_ID('rdb.dbo.Stageing_key_metadata_INV_EPIDEMIOLOGY', 'U') IS NOT NULL
		BEGIN
			DROP TABLE rdb.dbo.Stageing_key_metadata_INV_EPIDEMIOLOGY;
		END;
		--create table Stageing_key_metadata_INV_EPIDEMIOLOGY as 
		SELECT DISTINCT 
			   NRDBM.RDB_COLUMN_NM, NUIM.NBS_QUESTION_UID, NUIM.CODE_SET_GROUP_ID, NUIM.INVESTIGATION_FORM_CD, data_type, CODE_SET_GROUP_ID AS CODE_SET_GROUP_ID1, QUESTION_GROUP_SEQ_NBR, DATA_TYPE AS DATA_TYPE1
		INTO rdb.dbo.Stageing_key_metadata_INV_EPIDEMIOLOGY
		FROM NBS_ODSE.dbo.NBS_RDB_METADATA AS NRDBM WITH(NOLOCK), NBS_ODSE.dbo.NBS_UI_METADATA AS NUIM WITH(NOLOCK)
		WHERE NRDBM.NBS_UI_METADATA_UID = NUIM.NBS_UI_METADATA_UID AND 
			  NRDBM.RDB_TABLE_NM = 'D_INV_EPIDEMIOLOGY' AND 
			  QUESTION_GROUP_SEQ_NBR IS NULL;
		SELECT @RowCount_no = @@ROWCOUNT;
		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_EPIDEMIOLOGY', 'RDB.S_INV_EPIDEMIOLOGY', 'START', @Proc_Step_no, @Proc_Step_Name, @RowCount_no );

		COMMIT TRANSACTION;

		BEGIN TRANSACTION;
		SET @Proc_Step_no = 53;
		SET @Proc_Step_Name = ' Generating STAGING_KEY_INV_EPIDEMIOLOGY'; 
		--create table STAGING_KEY AS 
		IF OBJECT_ID('rdb.dbo.STAGING_KEY_INV_EPIDEMIOLOGY', 'U') IS NOT NULL
		BEGIN
			DROP TABLE rdb.dbo.STAGING_KEY_INV_EPIDEMIOLOGY;
		END;

		SELECT ACT_UID AS PAGE_CASE_UID, NBS_CASE_ANSWER_UID, PHC_UIDS.LAST_CHG_TIME
		INTO rdb.dbo.STAGING_KEY_INV_EPIDEMIOLOGY
		FROM rdb.dbo.Stageing_key_metadata_INV_EPIDEMIOLOGY AS NUIM WITH(NOLOCK)
			 INNER JOIN
			 NBS_ODSE.dbo.NBS_CASE_ANSWER AS PA WITH(NOLOCK)
			 ON NUIM.NBS_QUESTION_UID = PA.NBS_QUESTION_UID
			 INNER JOIN
			 RDB.dbo.PHC_UIDS WITH(NOLOCK)
			 ON PHC_UIDS.PAGE_CASE_UID = PA.ACT_UID
		WHERE ANSWER_GROUP_SEQ_NBR IS NULL
		GROUP BY ACT_UID, NBS_CASE_ANSWER_UID, PHC_UIDS.LAST_CHG_TIME;
		IF OBJECT_ID('rdb.dbo.STAGING_KEY_INV_EPIDEMIOLOGY_FINAL', 'U') IS NOT NULL
		BEGIN
			DROP TABLE rdb.dbo.STAGING_KEY_INV_EPIDEMIOLOGY_FINAL;
		END;

		SELECT *
		INTO [RDB].[dbo].[STAGING_KEY_INV_EPIDEMIOLOGY_FINAL]
		FROM
		(
			SELECT *, ROW_NUMBER() OVER(PARTITION BY [page_case_uid]
			ORDER BY [page_case_uid], NBS_CASE_ANSWER_UID) AS rowid
			FROM [RDB].[dbo].[STAGING_KEY_INV_EPIDEMIOLOGY]
		) AS Der
		WHERE rowid = 1;
		SELECT @RowCount_no = @@ROWCOUNT;
		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_EPIDEMIOLOGY', 'RDB.S_INV_EPIDEMIOLOGY', 'START', @Proc_Step_no, @Proc_Step_Name, @RowCount_no );

		COMMIT TRANSACTION;

		BEGIN TRANSACTION;
		SET @Proc_Step_no = 54;
		SET @Proc_Step_Name = ' Creating Table S_INV_EPIDEMIOLOGY'; 
    
	
		--CREATE TABLE 	S_INV_EPIDEMIOLOGY 
		IF OBJECT_ID('rdb.dbo.NUMERIC_DATA_OUT_INV_EPIDEMIOLOGY', 'U') IS NULL
		BEGIN
			CREATE TABLE [dbo].[NUMERIC_DATA_OUT_INV_EPIDEMIOLOGY]
			( 
						 [PAGE_CASE_UID_numeric] [bigint] NULL,
			)
			ON [PRIMARY];
		END;
		IF OBJECT_ID('rdb.dbo.date_data_INV_EPIDEMIOLOGY_out', 'U') IS NULL
		BEGIN
			CREATE TABLE [dbo].[date_data_INV_EPIDEMIOLOGY_out]
			( 
						 [PAGE_CASE_UID_date] [bigint] NULL,
			)
			ON [PRIMARY];
		END;
		IF OBJECT_ID('rdb.dbo.CODED_DATA_INV_EPIDEMIOLOGY_out', 'U') IS NULL
		BEGIN
			CREATE TABLE [dbo].[CODED_DATA_INV_EPIDEMIOLOGY_out]
			( 
						 [PAGE_CASE_UID_coded] [bigint] NULL,
			)
			ON [PRIMARY];
		END;
		IF OBJECT_ID('rdb.dbo.text_data_INV_EPIDEMIOLOGY_out', 'U') IS NULL
		BEGIN
			CREATE TABLE [dbo].[text_data_INV_EPIDEMIOLOGY_out]
			( 
						 [PAGE_CASE_UID_text] [bigint] NULL,
			)
			ON [PRIMARY];
		END;
		IF OBJECT_ID('rdb.dbo.S_INV_EPIDEMIOLOGY', 'U') IS NOT NULL
		BEGIN
			DROP TABLE rdb.dbo.S_INV_EPIDEMIOLOGY;
		END;
		--select * from 	 rdb.dbo.CODED_DATA_INV_EPIDEMIOLOGY_out;
		SELECT sk.*, ndo.*, ddo.*, cdo.*, tdo.*
		INTO rdb.dbo.S_INV_EPIDEMIOLOGY
		FROM rdb.dbo.STAGING_KEY_INV_EPIDEMIOLOGY_FINAL AS sk LEFT
			 OUTER JOIN
			 rdb.dbo.NUMERIC_DATA_OUT_INV_EPIDEMIOLOGY AS ndo
			 ON ndo.PAGE_CASE_UID_NUMERIC = sk.PAGE_CASE_UID LEFT
															  OUTER JOIN
															  rdb.dbo.date_data_INV_EPIDEMIOLOGY_out AS ddo
															  ON ddo.PAGE_CASE_UID_date = sk.PAGE_CASE_UID LEFT
															 OUTER JOIN
															 rdb.dbo.CODED_DATA_INV_EPIDEMIOLOGY_out AS cdo
															 ON cdo.PAGE_CASE_UID_coded = sk.PAGE_CASE_UID LEFT
																										   OUTER JOIN
																										   rdb.dbo.text_data_INV_EPIDEMIOLOGY_OUT AS tdo
																										   ON tdo.PAGE_CASE_UID_text = sk.PAGE_CASE_UID;
		SELECT @RowCount_no = @@ROWCOUNT;
		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_EPIDEMIOLOGY', 'RDB.S_INV_EPIDEMIOLOGY', 'START', @Proc_Step_no, @Proc_Step_Name, @RowCount_no );

		COMMIT TRANSACTION;
		ALTER TABLE rdb.dbo.S_INV_EPIDEMIOLOGY DROP COLUMN rowid;
		ALTER TABLE rdb.dbo.S_INV_EPIDEMIOLOGY DROP COLUMN PAGE_CASE_UID_numeric;
		ALTER TABLE rdb.dbo.S_INV_EPIDEMIOLOGY DROP COLUMN PAGE_CASE_UID_date;
		ALTER TABLE rdb.dbo.S_INV_EPIDEMIOLOGY DROP COLUMN PAGE_CASE_UID_coded;
		ALTER TABLE rdb.dbo.S_INV_EPIDEMIOLOGY DROP COLUMN PAGE_CASE_UID_text;
		IF OBJECT_ID('rdb.dbo.RDB_UI_METADATA_INV_EPIDEMIOLOGY_TEMP', 'U') IS NOT NULL
