		SET @sql = N'
SELECT [PAGE_CASE_UID] as PAGE_CASE_UID_NUMERIC, ' + STUFF(@columns, 1, 2, '') + ' into rdb.dbo.NUMERIC_DATA_PIVOT_INV_HIV ' + 'FROM (
