		UPDATE CODED_TABLE_SNTEMP_TRANS_A_INV_ISOLATE_TRACKING
		  SET CODE_SET_NM = a.CODE_SET_NM, ANSWER_TXT_CODE = '', ANSWER_TXT2 = '', code = ''
		FROM
		(
			SELECT TOP 1 CODE_SET_NM, NBS_QUESTION_UID
			FROM CODED_TABLE_SNTEMP_TRANS_A_INV_ISOLATE_TRACKING
			WHERE CODE_SET_NM IS NOT NULL
		) AS a
		WHERE CODED_TABLE_SNTEMP_TRANS_A_INV_ISOLATE_TRACKING.NBS_QUESTION_UID = a.NBS_QUESTION_UID AND 
