		SET @Proc_Step_Name = ' UPDATE TABLE  CODED_TABLE_SNTEMP_TRANS_CODE_INV_ISOLATE_TRACKING';
		IF OBJECT_ID('rdb.dbo.CODED_TABLE_SNTEMP_TRANS_CODE_INV_ISOLATE_TRACKING', 'U') IS NOT NULL
