		SET @Proc_Step_Name = ' UPDATE TABLE  CODED_TABLE_SNTEMP_TRANS_CODE_INV_ISOLATE_TRACKING';
		UPDATE RDB.dbo.CODED_TABLE_SNTEMP_TRANS_CODE_INV_ISOLATE_TRACKING
		  SET RDB_COLUMN_NM = REPLACE(SUBSTRING(RDB_COLUMN_NM, 1, 25) + '_UNIT', ' ', ''), ANSWER_TXT = REPLACE(ANSWER_TXT2, '  ', ' ')
		WHERE LEN(mask) > 0;
		--alter table  RDB.dbo.CODED_TABLE_SNTEMP_TRANS_CODE_INV_ISOLATE_TRACKING     drop column CODE_SET_GROUP_ID	;
		SELECT @RowCount_no = @@ROWCOUNT;
		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_ISOLATE_TRACKING', 'RDB.S_INV_ISOLATE_TRACKING', 'START', @Proc_Step_no, @Proc_Step_Name, @RowCount_no );

