		BEGIN
			SELECT *
			INTO rdb.dbo.NUMERIC_DATA_OUT_INV_ISOLATE_TRACKING
			FROM rdb.dbo.NUMERIC_DATA_PIVOT_INV_ISOLATE_TRACKING
			WHERE 
			---??? LEN(RTRIM(_LABEL_))>0    AND 
			PAGE_CASE_UID_NUMERIC > 0;
		END;
