		BEGIN TRANSACTION;
		SET @Proc_Step_no = 14;
		SET @Proc_Step_Name = ' Update  RDB_UI_METADATA_INV_MEDICAL_HISTORY';
		UPDATE rdb.dbo.RDB_UI_METADATA_INV_MEDICAL_HISTORY
