		BEGIN TRANSACTION;
		SET @Proc_Step_no = 20;
		SET @Proc_Step_Name = ' UPDATE TABLE  CODED_TABLE_SNTEMP_TRANS_A_INV_MEDICAL_HISTORY';

		UPDATE RDB.dbo.CODED_TABLE_SNTEMP_TRANS_A_INV_MEDICAL_HISTORY
		  SET ANSWER_TXT = REPLACE(ANSWER_VALUE, ' ', '')
		WHERE LEN(mask) > 0;
		UPDATE RDB.dbo.CODED_TABLE_SNTEMP_TRANS_A_INV_MEDICAL_HISTORY
		  SET ANSWER_TXT = REPLACE(ANSWER_VALUE, ' ', '') + ' ' + REPLACE(ANSWER_TXT2, ' ', '')
		WHERE LEN(mask) = 0;
		SELECT @RowCount_no = -1;
		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_MEDICAL_HISTORY', 'RDB.S_INV_MEDICAL_HISTORY', 'START', @Proc_Step_no, @Proc_Step_Name, @RowCount_no );

		COMMIT TRANSACTION;

		BEGIN TRANSACTION;
		SET @Proc_Step_no = 21;
		SET @Proc_Step_Name = ' UPDATE TABLE  CODED_TABLE_SNTEMP_TRANS_CODE_INV_MEDICAL_HISTORY';
		IF OBJECT_ID('rdb.dbo.CODED_TABLE_SNTEMP_TRANS_CODE_INV_MEDICAL_HISTORY', 'U') IS NOT NULL
		BEGIN
			DROP TABLE RDB.dbo.CODED_TABLE_SNTEMP_TRANS_CODE_INV_MEDICAL_HISTORY;
		END;

		SELECT *
		INTO RDB.dbo.CODED_TABLE_SNTEMP_TRANS_CODE_INV_MEDICAL_HISTORY
		FROM RDB.dbo.CODED_TABLE_SNTEMP_TRANS_A_INV_MEDICAL_HISTORY;
		SELECT @RowCount_no = @@ROWCOUNT;
		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_MEDICAL_HISTORY', 'RDB.S_INV_MEDICAL_HISTORY', 'START', @Proc_Step_no, @Proc_Step_Name, @RowCount_no );

