		BEGIN TRANSACTION;
		SET @Proc_Step_no = 27;
		SET @Proc_Step_Name = 'CREATE TABLE CODED_TABLE_MERGED_INV_MEDICAL_HISTORY';
		IF OBJECT_ID('rdb.dbo.CODED_TABLE_MERGED_TEMP_INV_MEDICAL_HISTORY', 'U') IS NOT NULL
