		BEGIN TRANSACTION;
		SET @Proc_Step_no = 32;
		SET @Proc_Step_Name = ' UPDATE TABLE date_data_INV_MEDICAL_HISTORY';
		UPDATE rdb.dbo.DATE_DATA_INV_MEDICAL_HISTORY
		  SET ANSWER_TXT1 = FORMAT(CAST([ANSWER_TXT] AS date), 'MM/dd/yy') + ' 00:00:00';
		--SET ANSWER_TXT=dhms(input(ANSWER_TXT1,MMDDYY10.),0,0,0); 
