		BEGIN
			DROP TABLE rdb.dbo.NUMERIC_DATA_PIVOT_INV_OTHER;
		END;
		SET @columns = N'';
		SELECT @columns+=N', p.' + QUOTENAME(LTRIM(RTRIM([RDB_COLUMN_NM])))
		FROM
		(
			SELECT [RDB_COLUMN_NM]
			FROM [dbo].NUMERIC_DATA_TRANS1_INV_OTHER AS p
