					CONDITION_CODE.INVESTIGATION_FORM_CD = NBS_UI_METADATA.INVESTIGATION_FORM_CD
			WHERE (isNumeric(ANSWER_VALUE) != 1) AND 
				  ANSWER_VALUE IS NOT NULL);
		
