		UPDATE rdb.dbo.CODED_TABLE_INV_RISK_FACTOR
		  SET ANSWER_TXT1 = ANSWER_TXT
		WHERE RTRIM(ANSWER_TXT1) = '';
		IF OBJECT_ID('rdb.dbo.CODED_TABLE_DESC_INV_RISK_FACTOR_TEMP', 'U') IS NOT NULL
