		GROUP BY PAGE_CASE_UID, NBS_QUESTION_UID;
		IF OBJECT_ID('rdb.dbo.CODED_COUNTY_TABLE_DESC_INV_RISK_FACTOR', 'U') IS NOT NULL
		BEGIN
