			 OUTER JOIN
			 rdb.dbo.CODED_COUNTY_TABLE_DESC_INV_RISK_FACTOR_TEMP AS cctt
			 ON cct.PAGE_CASE_UID = cctt.PAGE_CASE_UID AND 
				cct.NBS_QUESTION_UID = cctt.NBS_QUESTION_UID;
		SELECT @RowCount_no = @@ROWCOUNT;
		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_RISK_FACTOR', 'RDB.S_INV_RISK_FACTOR', 'START', @Proc_Step_no, @Proc_Step_Name, @RowCount_no );

		COMMIT TRANSACTION;

		BEGIN TRANSACTION;
		SET @Proc_Step_no = 27;
		SET @Proc_Step_Name = 'CREATE TABLE CODED_TABLE_MERGED_INV_RISK_FACTOR';
		IF OBJECT_ID('rdb.dbo.CODED_TABLE_MERGED_TEMP_INV_RISK_FACTOR', 'U') IS NOT NULL
