		END;
		--select * from 	 rdb.dbo.CODED_DATA_INV_SOCIAL_HISTORY_out;
		SELECT sk.*, ndo.*, ddo.*, cdo.*, tdo.*
		INTO rdb.dbo.S_INV_SOCIAL_HISTORY
		FROM rdb.dbo.STAGING_KEY_INV_SOCIAL_HISTORY_FINAL AS sk LEFT
			 OUTER JOIN
