		BEGIN
			DROP TABLE rdb.dbo.STAGING_KEY_INV_TREATMENT;
		END;
		IF OBJECT_ID('rdb.dbo.STAGING_KEY_INV_TREATMENT_FINAL', 'U') IS NOT NULL
		BEGIN
			DROP TABLE rdb.dbo.STAGING_KEY_INV_TREATMENT_FINAL;
		END;

		BEGIN TRANSACTION;
		SET @Proc_Step_no = 999;
		SET @Proc_Step_Name = 'SP_COMPLETE';
		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_TREATMENT', 'RDB.S_INV_TREATMENT', 'COMPLETE', @Proc_Step_no, @Proc_Step_name, @RowCount_no );

		COMMIT TRANSACTION;
	END TRY
	BEGIN CATCH
		IF @@TRANCOUNT > 0
		BEGIN
			ROLLBACK TRANSACTION;
		END;
		DECLARE @ErrorNumber int= ERROR_NUMBER();
		DECLARE @ErrorLine int= ERROR_LINE();
		DECLARE @ErrorMessage nvarchar(4000)= ERROR_MESSAGE();
		DECLARE @ErrorSeverity int= ERROR_SEVERITY();
		DECLARE @ErrorState int= ERROR_STATE();
		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [Error_Description], [row_count] )
		VALUES( @Batch_id, 'INV_TREATMENT', 'RDB.S_INV_TREATMENT', 'ERROR', @Proc_Step_no, 'ERROR - ' + @Proc_Step_name, 'Step -' + CAST(@Proc_Step_no AS varchar(3)) + ' -' + CAST(@ErrorMessage AS varchar(500)), 0 );
		RETURN -1;
	END CATCH;
END;
