			DROP TABLE rdb.dbo.NUMERIC_DATA_OUT_INV_TRAVEL;
		END;
		--CREATE TABLE NUMERIC_DATA_OUT 
		IF OBJECT_ID('rdb.dbo.NUMERIC_DATA_PIVOT_INV_TRAVEL', 'U') IS NOT NULL
		BEGIN
			SELECT *
			INTO rdb.dbo.NUMERIC_DATA_OUT_INV_TRAVEL
			FROM rdb.dbo.NUMERIC_DATA_PIVOT_INV_TRAVEL
			WHERE 
			---??? LEN(RTRIM(_LABEL_))>0    AND 
			PAGE_CASE_UID_NUMERIC > 0;
		END;
		---************************************************
		SELECT @RowCount_no = @@ROWCOUNT;
		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_TRAVEL', 'RDB.S_INV_TRAVEL', 'START', @Proc_Step_no, @Proc_Step_Name, @RowCount_no );

		COMMIT TRANSACTION;

		BEGIN TRANSACTION;
		SET @Proc_Step_no = 52;
		SET @Proc_Step_Name = ' Generating Stageing_key_metadata_INV_TRAVEL';
		IF OBJECT_ID('rdb.dbo.Stageing_key_metadata_INV_TRAVEL', 'U') IS NOT NULL
		BEGIN
			DROP TABLE rdb.dbo.Stageing_key_metadata_INV_TRAVEL;
		END;
		--create table Stageing_key_metadata_INV_TRAVEL as 
		SELECT DISTINCT 
			   NRDBM.RDB_COLUMN_NM, NUIM.NBS_QUESTION_UID, NUIM.CODE_SET_GROUP_ID, NUIM.INVESTIGATION_FORM_CD, data_type, CODE_SET_GROUP_ID AS CODE_SET_GROUP_ID1, QUESTION_GROUP_SEQ_NBR, DATA_TYPE AS DATA_TYPE1
		INTO rdb.dbo.Stageing_key_metadata_INV_TRAVEL
		FROM NBS_ODSE.dbo.NBS_RDB_METADATA AS NRDBM WITH(NOLOCK), NBS_ODSE.dbo.NBS_UI_METADATA AS NUIM WITH(NOLOCK)
		WHERE NRDBM.NBS_UI_METADATA_UID = NUIM.NBS_UI_METADATA_UID AND 
			  NRDBM.RDB_TABLE_NM = 'D_INV_TRAVEL' AND 
			  QUESTION_GROUP_SEQ_NBR IS NULL;
		SELECT @RowCount_no = @@ROWCOUNT;
		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_TRAVEL', 'RDB.S_INV_TRAVEL', 'START', @Proc_Step_no, @Proc_Step_Name, @RowCount_no );

