		BEGIN TRANSACTION;
		SET @Proc_Step_no = 53;
		SET @Proc_Step_Name = ' Generating STAGING_KEY_INV_TRAVEL'; 
		--create table STAGING_KEY AS 
		IF OBJECT_ID('rdb.dbo.STAGING_KEY_INV_TRAVEL', 'U') IS NOT NULL
		BEGIN
			DROP TABLE rdb.dbo.STAGING_KEY_INV_TRAVEL;
		END;

		SELECT ACT_UID AS PAGE_CASE_UID, NBS_CASE_ANSWER_UID, PHC_UIDS.LAST_CHG_TIME
		INTO rdb.dbo.STAGING_KEY_INV_TRAVEL
		FROM rdb.dbo.Stageing_key_metadata_INV_TRAVEL AS NUIM WITH(NOLOCK)
			 INNER JOIN
			 NBS_ODSE.dbo.NBS_CASE_ANSWER AS PA WITH(NOLOCK)
			 ON NUIM.NBS_QUESTION_UID = PA.NBS_QUESTION_UID
			 INNER JOIN
			 RDB.dbo.PHC_UIDS WITH(NOLOCK)
			 ON PHC_UIDS.PAGE_CASE_UID = PA.ACT_UID
		WHERE ANSWER_GROUP_SEQ_NBR IS NULL
		GROUP BY ACT_UID, NBS_CASE_ANSWER_UID, PHC_UIDS.LAST_CHG_TIME;
		IF OBJECT_ID('rdb.dbo.STAGING_KEY_INV_TRAVEL_FINAL', 'U') IS NOT NULL
		BEGIN
			DROP TABLE rdb.dbo.STAGING_KEY_INV_TRAVEL_FINAL;
		END;

		SELECT *
		INTO [RDB].[dbo].[STAGING_KEY_INV_TRAVEL_FINAL]
		FROM
		(
			SELECT *, ROW_NUMBER() OVER(PARTITION BY [page_case_uid]
			ORDER BY [page_case_uid], NBS_CASE_ANSWER_UID) AS rowid
			FROM [RDB].[dbo].[STAGING_KEY_INV_TRAVEL]
		) AS Der
		WHERE rowid = 1;
		SELECT @RowCount_no = @@ROWCOUNT;
		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_TRAVEL', 'RDB.S_INV_TRAVEL', 'START', @Proc_Step_no, @Proc_Step_Name, @RowCount_no );

		COMMIT TRANSACTION;

		BEGIN TRANSACTION;
		SET @Proc_Step_no = 54;
		SET @Proc_Step_Name = ' Creating Table S_INV_TRAVEL'; 
    
	
		--CREATE TABLE 	S_INV_TRAVEL 
		IF OBJECT_ID('rdb.dbo.NUMERIC_DATA_OUT_INV_TRAVEL', 'U') IS NULL
		BEGIN
			CREATE TABLE [dbo].[NUMERIC_DATA_OUT_INV_TRAVEL]
			( 
						 [PAGE_CASE_UID_numeric] [bigint] NULL,
			)
			ON [PRIMARY];
		END;
		IF OBJECT_ID('rdb.dbo.date_data_INV_TRAVEL_out', 'U') IS NULL
		BEGIN
			CREATE TABLE [dbo].[date_data_INV_TRAVEL_out]
			( 
						 [PAGE_CASE_UID_date] [bigint] NULL,
			)
			ON [PRIMARY];
		END;
		IF OBJECT_ID('rdb.dbo.CODED_DATA_INV_TRAVEL_out', 'U') IS NULL
		BEGIN
			CREATE TABLE [dbo].[CODED_DATA_INV_TRAVEL_out]
			( 
						 [PAGE_CASE_UID_coded] [bigint] NULL,
			)
			ON [PRIMARY];
		END;
		IF OBJECT_ID('rdb.dbo.text_data_INV_TRAVEL_out', 'U') IS NULL
		BEGIN
			CREATE TABLE [dbo].[text_data_INV_TRAVEL_out]
			( 
						 [PAGE_CASE_UID_text] [bigint] NULL,
			)
			ON [PRIMARY];
		END;
		IF OBJECT_ID('rdb.dbo.S_INV_TRAVEL', 'U') IS NOT NULL
		BEGIN
			DROP TABLE rdb.dbo.S_INV_TRAVEL;
		END;
		--select * from 	 rdb.dbo.CODED_DATA_INV_TRAVEL_out;
		SELECT sk.*, ndo.*, ddo.*, cdo.*, tdo.*
		INTO rdb.dbo.S_INV_TRAVEL
		FROM rdb.dbo.STAGING_KEY_INV_TRAVEL_FINAL AS sk LEFT
			 OUTER JOIN
			 rdb.dbo.NUMERIC_DATA_OUT_INV_TRAVEL AS ndo
			 ON ndo.PAGE_CASE_UID_NUMERIC = sk.PAGE_CASE_UID LEFT
														OUTER JOIN
														rdb.dbo.date_data_INV_TRAVEL_out AS ddo
														ON ddo.PAGE_CASE_UID_date = sk.PAGE_CASE_UID LEFT
															 OUTER JOIN
															 rdb.dbo.CODED_DATA_INV_TRAVEL_out AS cdo
															 ON cdo.PAGE_CASE_UID_coded = sk.PAGE_CASE_UID LEFT
																									 OUTER JOIN
																									 rdb.dbo.text_data_INV_TRAVEL_OUT AS tdo
																									 ON tdo.PAGE_CASE_UID_text = sk.PAGE_CASE_UID;
		SELECT @RowCount_no = @@ROWCOUNT;
