		BEGIN TRANSACTION;
		SET @Proc_Step_no = 14;
		SET @Proc_Step_Name = ' Update  RDB_UI_METADATA_INV_UNDER_CONDITION';
		UPDATE rdb.dbo.RDB_UI_METADATA_INV_UNDER_CONDITION
		  SET CODE_SET_GROUP_ID = unit_value
		WHERE RTRIM(CODE_SET_GROUP_ID) IS NULL AND 
			  UNIT_TYPE_CD = 'CODED';
		SELECT @RowCount_no = @@ROWCOUNT;
		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_UNDER_CONDITION', 'RDB.S_INV_UNDER_CONDITION', 'START', @Proc_Step_no, @Proc_Step_Name, @RowCount_no );

		COMMIT TRANSACTION;

		BEGIN TRANSACTION;
		SET @Proc_Step_no = 15;
		SET @Proc_Step_Name = ' Create table CODED_TABLE_SNTEMP_INV_UNDER_CONDITION'; 
		-- CREATE TABLE CODED_TABLE_SNTEMP AS
		IF OBJECT_ID('rdb.dbo.CODED_TABLE_SNTEMP_INV_UNDER_CONDITION', 'U') IS NOT NULL
		BEGIN
			DROP TABLE rdb.dbo.CODED_TABLE_SNTEMP_INV_UNDER_CONDITION;
		END;

		SELECT NBS_CASE_ANSWER_UID, rmeta.CODE_SET_GROUP_ID, RDB_COLUMN_NM, CAST(ANSWER_TXT AS varchar(2000)) AS ANSWER_TXT, ACT_UID AS 'PAGE_CASE_UID', PA.RECORD_STATUS_CD, rmeta.NBS_QUESTION_UID, MASK, CAST(NULL AS [varchar](2000)) AS ANSWER_TXT_CODE, CAST(NULL AS [varchar](2000)) AS ANSWER_VALUE, PHC_UIDS.INVESTIGATION_FORM_CD
		INTO rdb.dbo.CODED_TABLE_SNTEMP_INV_UNDER_CONDITION
		FROM rdb.dbo.RDB_UI_METADATA_INV_UNDER_CONDITION AS rmeta WITH(NOLOCK) LEFT
			 OUTER JOIN
			 NBS_ODSE.[dbo].NBS_CASE_ANSWER AS PA WITH(NOLOCK)
			 ON rmeta.nbs_question_uid = PA.nbs_question_uid AND 
				pa.ANSWER_GROUP_SEQ_NBR IS NULL LEFT
																			   OUTER JOIN
																			   PHC_UIDS
																			   ON PHC_UIDS.PAGE_CASE_UID = PA.act_uid
												INNER JOIN
												NBS_SRTE.dbo.CODE_VALUE_GENERAL AS CVG WITH(NOLOCK)
												ON UPPER(CVG.CODE) = UPPER(rmeta.DATA_TYPE)
		WHERE CVG.CODE_SET_NM = 'NBS_DATA_TYPE' AND 
			  UPPER(data_type) = 'NUMERIC'
		ORDER BY ACT_UID, NBS_CASE_ANSWER_UID, rmeta.CODE_SET_GROUP_ID;
		SELECT @RowCount_no = @@ROWCOUNT;
		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_UNDER_CONDITION', 'RDB.S_INV_UNDER_CONDITION', 'START', @Proc_Step_no, @Proc_Step_Name, @RowCount_no );

		COMMIT TRANSACTION;

		BEGIN TRANSACTION;
		SET @Proc_Step_no = 17;
		SET @Proc_Step_Name = ' Ceate TABLE   CODED_TABLE_SNTEMP_INV_UNDER_CONDITION';
		UPDATE rdb.dbo.CODED_TABLE_SNTEMP_INV_UNDER_CONDITION
		  SET ANSWER_TXT_CODE = SUBSTRING(ANSWER_TXT, CHARINDEX('^', ANSWER_TXT) + 1, LEN(RTRIM(ANSWER_TXT))), ANSWER_VALUE = REPLACE(SUBSTRING(ANSWER_TXT, 1, ( CHARINDEX('^', ANSWER_TXT) - 1 )), ',', '')
		WHERE CHARINDEX('^', ANSWER_TXT) > 0;
		UPDATE rdb.dbo.CODED_TABLE_SNTEMP_INV_UNDER_CONDITION
		  SET ANSWER_VALUE = answer_txt
		WHERE ISNUMERIC(answer_txt) = 1;

		SELECT @RowCount_no = @@ROWCOUNT;
		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_UNDER_CONDITION', 'RDB.S_INV_UNDER_CONDITION', 'START', @Proc_Step_no, @Proc_Step_Name, @RowCount_no );

		COMMIT TRANSACTION;
	BEGIN TRANSACTION;
		SET @Proc_Step_no = 18;
		SET @Proc_Step_Name = ' LOG Invalid Numeric data INTO ETL_DQ_LOG';
	
		INSERT INTO rdb.dbo.ETL_DQ_LOG( EVENT_TYPE, EVENT_LOCAL_ID, EVENT_UID, DQ_ISSUE_CD, DQ_ISSUE_DESC_TXT, DQ_ISSUE_QUESTION_IDENTIFIER, DQ_ISSUE_ANSWER_TXT, DQ_ISSUE_RDB_LOCATION, JOB_BATCH_LOG_UID, DQ_ETL_PROCESS_TABLE, DQ_ETL_PROCESS_COLUMN, DQ_STATUS_TIME, DQ_ISSUE_SOURCE_LOCATION, DQ_ISSUE_SOURCE_QUESTION_LABEL )
		(
		SELECT DISTINCT 'INVESTIGATION', PUBLIC_HEALTH_CASE.LOCAL_ID, PUBLIC_HEALTH_CASE_UID, 
		'INVALID_NUMERIC_VALUE', 'BAD NUMERIC VALUE: A non-numeric value exists in a field expecting a numeric value and requires update. Please correct the bad numeric value so that it can be properly written to the reporting database during the next ETL run', 
		NBS_UI_METADATA.QUESTION_IDENTIFIER, ANSWER_VALUE, NBS_UI_METADATA.DATA_LOCATION, @Batch_id, NBS_RDB_METADATA.rdb_table_nm, NBS_RDB_METADATA.RDB_COLUMN_NM, 
		GETDATE(), NBS_UI_METADATA.DATA_LOCATION, QUESTION_LABEL
					FROM rdb.dbo.CODED_TABLE_SNTEMP_INV_UNDER_CONDITION
			 INNER JOIN
				 NBS_ODSE.DBO.PUBLIC_HEALTH_CASE
				 ON CODED_TABLE_SNTEMP_INV_UNDER_CONDITION.page_case_uid= PUBLIC_HEALTH_CASE.PUBLIC_HEALTH_CASE_UID
				 INNER JOIN
				 NBS_SRTE.DBO.CONDITION_CODE
				 ON CONDITION_CODE.CONDITION_CD = PUBLIC_HEALTH_CASE.CD
				  INNER JOIN
				 NBS_ODSE.DBO.NBS_RDB_METADATA
				 ON NBS_RDB_METADATA.rdb_column_nm = CODED_TABLE_SNTEMP_INV_UNDER_CONDITION.rdb_column_nm
				 INNER JOIN
				 NBS_ODSE.DBO.NBS_UI_METADATA
				 ON NBS_RDB_METADATA.NBS_UI_METADATA_UID = NBS_UI_METADATA.NBS_UI_METADATA_UID AND 
					CONDITION_CODE.INVESTIGATION_FORM_CD = NBS_UI_METADATA.INVESTIGATION_FORM_CD
			WHERE (isNumeric(ANSWER_VALUE) != 1) AND 
				  ANSWER_VALUE IS NOT NULL);
		
		SELECT @RowCount_no = @@ROWCOUNT;
		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_UNDER_CONDITION', 'RDB.S_INV_UNDER_CONDITION', 'START', @Proc_Step_no, @Proc_Step_Name, @RowCount_no );
		COMMIT TRANSACTION;
		BEGIN TRANSACTION;
		SET @Proc_Step_no = 19;
		SET @Proc_Step_Name = ' Update  CODED_TABLE_SNTEMP_TRANS_A_INV_UNDER_CONDITION'; 
		--CREATE TABLE CODED_TABLE_SNTEMP_TRANS_A
		IF OBJECT_ID('rdb.dbo.CODED_TABLE_SNTEMP_TRANS_A_INV_UNDER_CONDITION', 'U') IS NOT NULL
		BEGIN
			DROP TABLE RDB.dbo.CODED_TABLE_SNTEMP_TRANS_A_INV_UNDER_CONDITION;
		END;

		SELECT 
		--CODED.CODE_SET_GROUP_ID, 
		  PAGE_CASE_UID, ANSWER_TXT_CODE, ANSWER_VALUE, NBS_CASE_ANSWER_UID, METADATA.CODE_SET_NM, RDB_COLUMN_NM, METADATA.CODE, CODE_SHORT_DESC_TXT AS 'ANSWER_TXT2', MASK, coded.NBS_QUESTION_UID, CAST(NULL AS varchar(2000)) AS ANSWER_TXT, METADATA.INVESTIGATION_FORM_CD
		INTO RDB.dbo.CODED_TABLE_SNTEMP_TRANS_A_INV_UNDER_CONDITION
		FROM rdb.dbo.CODED_TABLE_SNTEMP_INV_UNDER_CONDITION AS CODED WITH(NOLOCK) LEFT
			 JOIN
			 REF_FORMCODE_TRANSLATION AS METADATA WITH(NOLOCK)
			 ON METADATA.INVESTIGATION_FORM_CD = CODED.INVESTIGATION_FORM_CD AND 
				METADATA.CODE_SET_GROUP_ID = CODED.CODE_SET_GROUP_ID AND 
				METADATA.CODE = CODED.ANSWER_TXT_CODE
			 ORDER BY NBS_CASE_ANSWER_UID, RDB_COLUMN_NM;
		SELECT @RowCount_no = @@ROWCOUNT;
		UPDATE CODED_TABLE_SNTEMP_TRANS_A_INV_UNDER_CONDITION SET ANSWER_VALUE=NULL WHERE  ISNUMERIC(ANSWER_VALUE)!=1;
		UPDATE CODED_TABLE_SNTEMP_TRANS_A_INV_UNDER_CONDITION
		  SET CODE_SET_NM = a.CODE_SET_NM, ANSWER_TXT_CODE = '', ANSWER_TXT2 = '', code = ''
		FROM
		(
			SELECT TOP 1 CODE_SET_NM, NBS_QUESTION_UID
			FROM CODED_TABLE_SNTEMP_TRANS_A_INV_UNDER_CONDITION
			WHERE CODE_SET_NM IS NOT NULL
		) AS a
		WHERE CODED_TABLE_SNTEMP_TRANS_A_INV_UNDER_CONDITION.NBS_QUESTION_UID = a.NBS_QUESTION_UID AND 
			  CODED_TABLE_SNTEMP_TRANS_A_INV_UNDER_CONDITION.code_set_nm IS NULL;

		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_UNDER_CONDITION', 'RDB.S_INV_UNDER_CONDITION', 'START', @Proc_Step_no, @Proc_Step_Name, @RowCount_no );


		COMMIT TRANSACTION;


		BEGIN TRANSACTION;
		SET @Proc_Step_no = 20;
		SET @Proc_Step_Name = ' UPDATE TABLE  CODED_TABLE_SNTEMP_TRANS_A_INV_UNDER_CONDITION';

		UPDATE RDB.dbo.CODED_TABLE_SNTEMP_TRANS_A_INV_UNDER_CONDITION
		  SET ANSWER_TXT = REPLACE(ANSWER_VALUE, ' ', '')
		WHERE LEN(mask) > 0;
		UPDATE RDB.dbo.CODED_TABLE_SNTEMP_TRANS_A_INV_UNDER_CONDITION
		  SET ANSWER_TXT = REPLACE(ANSWER_VALUE, ' ', '') + ' ' + REPLACE(ANSWER_TXT2, ' ', '')
		WHERE LEN(mask) = 0;
		SELECT @RowCount_no = -1;
		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_UNDER_CONDITION', 'RDB.S_INV_UNDER_CONDITION', 'START', @Proc_Step_no, @Proc_Step_Name, @RowCount_no );

		COMMIT TRANSACTION;

		BEGIN TRANSACTION;
		SET @Proc_Step_no = 21;
		SET @Proc_Step_Name = ' UPDATE TABLE  CODED_TABLE_SNTEMP_TRANS_CODE_INV_UNDER_CONDITION';
		IF OBJECT_ID('rdb.dbo.CODED_TABLE_SNTEMP_TRANS_CODE_INV_UNDER_CONDITION', 'U') IS NOT NULL
		BEGIN
			DROP TABLE RDB.dbo.CODED_TABLE_SNTEMP_TRANS_CODE_INV_UNDER_CONDITION;
		END;

		SELECT *
		INTO RDB.dbo.CODED_TABLE_SNTEMP_TRANS_CODE_INV_UNDER_CONDITION
		FROM RDB.dbo.CODED_TABLE_SNTEMP_TRANS_A_INV_UNDER_CONDITION;
		SELECT @RowCount_no = @@ROWCOUNT;
		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_UNDER_CONDITION', 'RDB.S_INV_UNDER_CONDITION', 'START', @Proc_Step_no, @Proc_Step_Name, @RowCount_no );

		COMMIT TRANSACTION;

		BEGIN TRANSACTION;
		SET @Proc_Step_no = 22;
		SET @Proc_Step_Name = ' UPDATE TABLE  CODED_TABLE_SNTEMP_TRANS_CODE_INV_UNDER_CONDITION';
		UPDATE RDB.dbo.CODED_TABLE_SNTEMP_TRANS_CODE_INV_UNDER_CONDITION
		  SET RDB_COLUMN_NM = REPLACE(SUBSTRING(RDB_COLUMN_NM, 1, 25) + '_UNIT', ' ', ''), ANSWER_TXT = REPLACE(ANSWER_TXT2, '  ', ' ')
		WHERE LEN(mask) > 0;
		--alter table  RDB.dbo.CODED_TABLE_SNTEMP_TRANS_CODE_INV_UNDER_CONDITION     drop column CODE_SET_GROUP_ID	;
		SELECT @RowCount_no = @@ROWCOUNT;
		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_UNDER_CONDITION', 'RDB.S_INV_UNDER_CONDITION', 'START', @Proc_Step_no, @Proc_Step_Name, @RowCount_no );

		COMMIT TRANSACTION;

		BEGIN TRANSACTION;
		SET @Proc_Step_no = 23;
		SET @Proc_Step_Name = ' CREATE TABLE  CODED_TABLE_INV_UNDER_CONDITION';
		IF OBJECT_ID('rdb.dbo.CODED_TABLE_TEMP_INV_UNDER_CONDITION', 'U') IS NOT NULL
		BEGIN
			DROP TABLE rdb.dbo.CODED_TABLE_TEMP_INV_UNDER_CONDITION;
		END;
		IF OBJECT_ID('rdb.dbo.CODED_TABLE_INV_UNDER_CONDITION', 'U') IS NOT NULL
		BEGIN
			DROP TABLE rdb.dbo.CODED_TABLE_INV_UNDER_CONDITION;
		END;

		SELECT COALESCE(csnta.NBS_CASE_ANSWER_UID, csntc.NBS_CASE_ANSWER_UID) AS NBS_CASE_ANSWER_UID, COALESCE(csnta.RDB_COLUMN_NM, csntc.RDB_COLUMN_NM) AS RDB_COLUMN_NM, COALESCE(csnta.PAGE_CASE_UID, csntc.PAGE_CASE_UID) AS PAGE_CASE_UID, COALESCE(csnta.ANSWER_TXT_CODE, csntc.ANSWER_TXT_CODE) AS ANSWER_TXT_CODE, COALESCE(csnta.ANSWER_VALUE, csntc.ANSWER_VALUE) AS ANSWER_VALUE, COALESCE(csnta.CODE_SET_NM, csntc.CODE_SET_NM) AS CODE_SET_NM, COALESCE(csnta.CODE, csntc.CODE) AS CODE, COALESCE(csnta.ANSWER_TXT2, csntc.ANSWER_TXT2) AS ANSWER_TXT2, COALESCE(csnta.MASK, csntc.MASK) AS MASK, COALESCE(csnta.ANSWER_TXT, csntc.ANSWER_TXT) AS ANSWER_TXT, COALESCE(csnta.nbs_question_uid, csntc.nbs_question_uid) AS nbs_question_uid
		INTO rdb.dbo.CODED_TABLE_TEMP_INV_UNDER_CONDITION
		FROM [RDB].[dbo].CODED_TABLE_SNTEMP_TRANS_A_INV_UNDER_CONDITION AS csnta
			 FULL OUTER JOIN
			 [RDB].[dbo].CODED_TABLE_SNTEMP_TRANS_CODE_INV_UNDER_CONDITION AS csntc
			 ON csnta.NBS_CASE_ANSWER_UID = csntc.NBS_CASE_ANSWER_UID AND 
				csnta.[RDB_COLUMN_NM] = csntc.[RDB_COLUMN_NM];
		SELECT CODE_SET_GROUP_ID, COALESCE(csnta.PAGE_CASE_UID, csntt.[PAGE_CASE_UID]) AS [PAGE_CASE_UID], COALESCE(csnta.NBS_QUESTION_UID, csntt.NBS_QUESTION_UID) AS [NBS_QUESTION_UID], COALESCE(csnta.NBS_QUESTION_UID, csntt.[NBS_CASE_ANSWER_UID]) AS [NBS_CASE_ANSWER_UID], COALESCE(csnta.ANSWER_TXT, csntt.[ANSWER_TXT]) AS [ANSWER_TXT], COALESCE(csnta.CODE_SET_NM, csntt.[CODE_SET_NM]) AS [CODE_SET_NM], COALESCE(csnta.RDB_COLUMN_NM, csntt.[RDB_COLUMN_NM]) AS [RDB_COLUMN_NM], ANSWER_OTH, COALESCE(csnta.CODE, csntt.[CODE]) AS [CODE], csnta.ANSWER_TXT1, csntt.[ANSWER_TXT_CODE], csntt.[ANSWER_VALUE], csntt.[ANSWER_TXT2], csntt.[MASK]
		INTO rdb.dbo.CODED_TABLE_INV_UNDER_CONDITION
		FROM [RDB].[dbo].CODED_TABLE_STD_INV_UNDER_CONDITION AS csnta
			 FULL OUTER JOIN
			 [RDB].[dbo].CODED_TABLE_TEMP_INV_UNDER_CONDITION AS csntt
			 ON csnta.NBS_CASE_ANSWER_UID = csntt.NBS_CASE_ANSWER_UID AND 
				csnta.[RDB_COLUMN_NM] = csntt.[RDB_COLUMN_NM];
		SELECT @RowCount_no = @@ROWCOUNT;
		CREATE NONCLUSTERED INDEX [RDB_PERF_INTERNAL_02]
ON [dbo].[CODED_TABLE_INV_UNDER_CONDITION]
		( [CODE_SET_GROUP_ID]
		) 
			   INCLUDE( [PAGE_CASE_UID], [NBS_QUESTION_UID], [NBS_CASE_ANSWER_UID], [ANSWER_TXT], [RDB_COLUMN_NM], [ANSWER_OTH] );

		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_UNDER_CONDITION', 'RDB.S_INV_UNDER_CONDITION', 'START', @Proc_Step_no, @Proc_Step_Name, @RowCount_no );

		COMMIT TRANSACTION;

		BEGIN TRANSACTION;
		SET @Proc_Step_no = 24;
		SET @Proc_Step_Name = ' UPDATE TABLE  CODED_TABLE_INV_UNDER_CONDITION';
		UPDATE rdb.dbo.CODED_TABLE_INV_UNDER_CONDITION
		  SET ANSWER_TXT1 = ANSWER_TXT
		WHERE RTRIM(ANSWER_TXT1) = '';
		IF OBJECT_ID('rdb.dbo.CODED_TABLE_DESC_INV_UNDER_CONDITION_TEMP', 'U') IS NOT NULL
		BEGIN
			DROP TABLE rdb.dbo.CODED_TABLE_DESC_INV_UNDER_CONDITION_TEMP;
		END;

		SELECT p1.PAGE_CASE_UID, p1.NBS_QUESTION_UID, STUFF(
		(
			SELECT TOP 10 ' | ' + ANSWER_TXT1
			FROM [RDB].[dbo].[CODED_TABLE_INV_UNDER_CONDITION] AS p2
			WHERE p2.PAGE_CASE_UID = p1.PAGE_CASE_UID AND 
				  p2.nbs_question_uid = p1.NBS_QUESTION_UID
			ORDER BY PAGE_CASE_UID, NBS_QUESTION_UID, NBS_CASE_ANSWER_UID FOR XML PATH(''), TYPE
		).value( '.', 'varchar(2000)' ), 1, 3, '') AS ANSWER_DESC11
		INTO [RDB].[dbo].[CODED_TABLE_DESC_INV_UNDER_CONDITION_TEMP]
		FROM [RDB].[dbo].[CODED_TABLE_INV_UNDER_CONDITION] AS p1
		--where  nbs_question_uid is not null
		GROUP BY PAGE_CASE_UID, RDB_COLUMN_NM, NBS_QUESTION_UID;
		IF OBJECT_ID('rdb.dbo.CODED_TABLE_DESC_INV_UNDER_CONDITION', 'U') IS NOT NULL
		BEGIN
			DROP TABLE rdb.dbo.CODED_TABLE_DESC_INV_UNDER_CONDITION;
		END;

		SELECT ct.*, COALESCE(ctt.answer_desc11, ct.answer_txt1) AS answer_desc11
		INTO rdb.dbo.CODED_TABLE_DESC_INV_UNDER_CONDITION
		FROM [RDB].[dbo].[CODED_TABLE_INV_UNDER_CONDITION] AS ct LEFT
			 OUTER JOIN
			 [CODED_TABLE_DESC_INV_UNDER_CONDITION_TEMP] AS ctt
			 ON ct.PAGE_CASE_UID = ctt.PAGE_CASE_UID AND 
				ct.NBS_QUESTION_UID = ctt.NBS_QUESTION_UID;
		SELECT @RowCount_no = @@ROWCOUNT;
		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_UNDER_CONDITION', 'RDB.S_INV_UNDER_CONDITION', 'START', @Proc_Step_no, @Proc_Step_Name, @RowCount_no );

		COMMIT TRANSACTION;

		BEGIN TRANSACTION;
		SET @Proc_Step_no = 26;
		SET @Proc_Step_Name = 'CREATE TABLE  CODED_COUNTY_TABLE_INV_UNDER_CONDITION'; 
		--CREATE TABLE 	CODED_COUNTY_TABLE 
		IF OBJECT_ID('rdb.dbo.CODED_COUNTY_TABLE_INV_UNDER_CONDITION', 'U') IS NOT NULL
		BEGIN
			DROP TABLE rdb.dbo.CODED_COUNTY_TABLE_INV_UNDER_CONDITION;
		END;

		SELECT CODED.CODE_SET_GROUP_ID, PAGE_CASE_UID, NBS_QUESTION_UID, NBS_CASE_ANSWER_UID, ANSWER_TXT, CVG.CODE_SET_NM, RDB_COLUMN_NM, ANSWER_OTH, CVG.CODE, CODE_SHORT_DESC_TXT AS 'ANSWER_TXT1'
		INTO rdb.dbo.CODED_COUNTY_TABLE_INV_UNDER_CONDITION
		FROM rdb.dbo.CODED_TABLE_INV_UNDER_CONDITION AS CODED WITH(NOLOCK) LEFT
			 JOIN
			 NBS_SRTE.dbo.CODESET_GROUP_METADATA AS METADATA WITH(NOLOCK)
			 ON METADATA.CODE_SET_GROUP_ID = CODED.CODE_SET_GROUP_ID LEFT
																		   JOIN
																		   NBS_SRTE.dbo.V_STATE_COUNTY_CODE_VALUE AS CVG WITH(NOLOCK)
																		   ON CVG.CODE_SET_NM = METADATA.CODE_SET_NM AND 
																			  CVG.CODE = CODED.ANSWER_TXT
		WHERE METADATA.CODE_SET_NM = 'COUNTY_CCD';
		IF OBJECT_ID('rdb.dbo.CODED_COUNTY_TABLE_DESC_INV_UNDER_CONDITION_TEMP', 'U') IS NOT NULL
		BEGIN
			DROP TABLE rdb.dbo.CODED_COUNTY_TABLE_DESC_INV_UNDER_CONDITION_TEMP;
		END;

		SELECT p1.PAGE_CASE_UID, p1.NBS_QUESTION_UID, STUFF(
		(
			SELECT TOP 10 ' |' + ANSWER_TXT1
			FROM [RDB].[dbo].[CODED_COUNTY_TABLE_INV_UNDER_CONDITION] AS p2
			WHERE p2.PAGE_CASE_UID = p1.PAGE_CASE_UID AND 
				  p2.nbs_question_uid = p1.NBS_QUESTION_UID
			ORDER BY PAGE_CASE_UID, NBS_QUESTION_UID, NBS_CASE_ANSWER_UID FOR XML PATH(''), TYPE
		).value( '.', 'varchar(2000)' ), 1, 2, '') AS ANSWER_DESC11
		INTO [RDB].[dbo].[CODED_COUNTY_TABLE_DESC_INV_UNDER_CONDITION_TEMP]
		FROM [RDB].[dbo].[CODED_COUNTY_TABLE_INV_UNDER_CONDITION] AS p1
		GROUP BY PAGE_CASE_UID, NBS_QUESTION_UID;
		IF OBJECT_ID('rdb.dbo.CODED_COUNTY_TABLE_DESC_INV_UNDER_CONDITION', 'U') IS NOT NULL
		BEGIN
			DROP TABLE rdb.dbo.CODED_COUNTY_TABLE_DESC_INV_UNDER_CONDITION;
		END;

		SELECT cct.*, cctt.answer_desc11
		INTO [RDB].[dbo].[CODED_COUNTY_TABLE_DESC_INV_UNDER_CONDITION]
		FROM [RDB].[dbo].[CODED_COUNTY_TABLE_INV_UNDER_CONDITION] AS cct LEFT
			 OUTER JOIN
			 rdb.dbo.CODED_COUNTY_TABLE_DESC_INV_UNDER_CONDITION_TEMP AS cctt
			 ON cct.PAGE_CASE_UID = cctt.PAGE_CASE_UID AND 
				cct.NBS_QUESTION_UID = cctt.NBS_QUESTION_UID;
		SELECT @RowCount_no = @@ROWCOUNT;
		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_UNDER_CONDITION', 'RDB.S_INV_UNDER_CONDITION', 'START', @Proc_Step_no, @Proc_Step_Name, @RowCount_no );

		COMMIT TRANSACTION;

		BEGIN TRANSACTION;
		SET @Proc_Step_no = 27;
		SET @Proc_Step_Name = 'CREATE TABLE CODED_TABLE_MERGED_INV_UNDER_CONDITION';
		IF OBJECT_ID('rdb.dbo.CODED_TABLE_MERGED_TEMP_INV_UNDER_CONDITION', 'U') IS NOT NULL
		BEGIN
			DROP TABLE rdb.dbo.CODED_TABLE_MERGED_TEMP_INV_UNDER_CONDITION;
		END;
		IF OBJECT_ID('rdb.dbo.CODED_TABLE_MERGED_INV_UNDER_CONDITION', 'U') IS NOT NULL
		BEGIN
			DROP TABLE rdb.dbo.CODED_TABLE_MERGED_INV_UNDER_CONDITION;
		END;

		SELECT temp_tbl.*
		INTO rdb.dbo.CODED_TABLE_MERGED_INV_UNDER_CONDITION
		FROM
		(
			SELECT [CODE_SET_GROUP_ID], [PAGE_CASE_UID], [NBS_QUESTION_UID], [NBS_CASE_ANSWER_UID], [ANSWER_TXT], [CODE_SET_NM], [RDB_COLUMN_NM], [ANSWER_OTH], [CODE], [ANSWER_TXT1], [answer_desc11], [ANSWER_TXT_CODE], [ANSWER_VALUE], [ANSWER_TXT2], [MASK], NULL AS OTHER_VALUE_IND_CD, NULL AS RDB_COLUMN_NM2
			FROM [RDB].[dbo].[CODED_TABLE_DESC_INV_UNDER_CONDITION]
			UNION ALL
			SELECT [CODE_SET_GROUP_ID], [PAGE_CASE_UID], [NBS_QUESTION_UID], [NBS_CASE_ANSWER_UID], [ANSWER_TXT], [CODE_SET_NM], [RDB_COLUMN_NM], [ANSWER_OTH], [CODE], [ANSWER_TXT1], [answer_desc11], NULL, NULL, NULL, NULL, NULL, NULL
			FROM [RDB].[dbo].[CODED_COUNTY_TABLE_DESC_INV_UNDER_CONDITION]
			UNION ALL
			SELECT [CODE_SET_GROUP_ID], [PAGE_CASE_UID], [NBS_CASE_ANSWER_UID], [NBS_QUESTION_UID], [ANSWER_TXT], NULL, [RDB_COLUMN_NM], NULL, NULL, NULL, [ANSWER_DESC11], NULL, NULL, NULL, NULL, [OTHER_VALUE_IND_CD], [RDB_COLUMN_NM2]
			FROM [RDB].[dbo].[CODED_TABLE_OTHER_INV_UNDER_CONDITION]
		) AS temp_tbl;
		CREATE NONCLUSTERED INDEX [RDB_PERF_INTERNAL_04]
ON [dbo].[CODED_TABLE_MERGED_INV_UNDER_CONDITION]
		( [RDB_COLUMN_NM]
		);

		SELECT @RowCount_no = @@ROWCOUNT;
		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_UNDER_CONDITION', 'RDB.S_INV_UNDER_CONDITION', 'START', @Proc_Step_no, @Proc_Step_Name, @RowCount_no );

		COMMIT TRANSACTION;

		BEGIN TRANSACTION;
		SET @Proc_Step_no = 30;
		SET @Proc_Step_Name = ' CREATE TABLE  RDB_UI_METADATA_INV_UNDER_CONDITION'; 
		-- create table rdb_ui_metadata as 
		IF OBJECT_ID('rdb.dbo.RDB_UI_METADATA_INV_UNDER_CONDITION_TEMP', 'U') IS NOT NULL
		BEGIN
			DROP TABLE rdb.dbo.RDB_UI_METADATA_INV_UNDER_CONDITION_TEMP;
		END;

		SELECT DISTINCT 
			   NRDBM.RDB_COLUMN_NM, NUIM.NBS_QUESTION_UID, NUIM.CODE_SET_GROUP_ID, NUIM.INVESTIGATION_FORM_CD, CODE_SET_GROUP_ID AS CODE_SET_GROUP_ID1, QUESTION_GROUP_SEQ_NBR, DATA_TYPE
		INTO rdb.dbo.RDB_UI_METADATA_INV_UNDER_CONDITION_TEMP
		FROM NBS_ODSE.[dbo].NBS_RDB_METADATA AS NRDBM WITH(NOLOCK), NBS_ODSE.[dbo].NBS_UI_METADATA AS NUIM WITH(NOLOCK)
		WHERE NRDBM.NBS_UI_METADATA_UID = NUIM.NBS_UI_METADATA_UID AND 
			  NRDBM.RDB_TABLE_NM = 'D_INV_UNDER_CONDITION' AND 
			  QUESTION_GROUP_SEQ_NBR IS NULL AND 
			  DATA_TYPE IN( 'Date/Time', 'Date', 'DATETIME', 'DATE' );
		IF OBJECT_ID('rdb.dbo.RDB_UI_METADATA_INV_UNDER_CONDITION', 'U') IS NOT NULL
		BEGIN
			DROP TABLE rdb.dbo.RDB_UI_METADATA_INV_UNDER_CONDITION;
		END;

		SELECT *
		INTO [RDB].[dbo].RDB_UI_METADATA_INV_UNDER_CONDITION
		FROM
		(
			SELECT *, ROW_NUMBER() OVER(PARTITION BY NBS_QUESTION_UID
			ORDER BY NBS_QUESTION_UID) AS rowid
			FROM [RDB].[dbo].RDB_UI_METADATA_INV_UNDER_CONDITION_TEMP
		) AS Der
		WHERE rowid = 1;
		SELECT @RowCount_no = @@ROWCOUNT;
		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_UNDER_CONDITION', 'RDB.S_INV_UNDER_CONDITION', 'START', @Proc_Step_no, @Proc_Step_Name, @RowCount_no );

		COMMIT TRANSACTION;

		BEGIN TRANSACTION;
		SET @Proc_Step_no = 31;
		SET @Proc_Step_Name = ' CREATE TABLE DATE_DATA_INV_UNDER_CONDITION'; 
		-- CREATE TABLE DATE_DATA AS
		IF OBJECT_ID('rdb.dbo.DATE_DATA_INV_UNDER_CONDITION', 'U') IS NOT NULL
		BEGIN
			DROP TABLE rdb.dbo.DATE_DATA_INV_UNDER_CONDITION;
		END;

		SELECT NBS_CASE_ANSWER_UID, rmeta.CODE_SET_GROUP_ID, RDB_COLUMN_NM, ( CASE
																			  WHEN ISDATE(ANSWER_TXT) = 1 THEN ANSWER_TXT
																			  ELSE NULL
																			  END ) AS ANSWER_TXT1, ACT_UID AS PAGE_CASE_UID, PA.RECORD_STATUS_CD, rmeta.NBS_QUESTION_UID, ( CASE
																																											 WHEN ISDATE(ANSWER_TXT) = 1 THEN ANSWER_TXT
																																											 ELSE NULL
																																											 END ) AS ANSWER_TXT
		INTO rdb.dbo.DATE_DATA_INV_UNDER_CONDITION
		FROM rdb.dbo.RDB_UI_METADATA_INV_UNDER_CONDITION AS rmeta WITH(NOLOCK) LEFT
			 OUTER JOIN
			 NBS_ODSE.[dbo].NBS_CASE_ANSWER AS PA WITH(NOLOCK)
			 ON rmeta.nbs_question_uid = PA.nbs_question_uid AND 
				pa.ANSWER_GROUP_SEQ_NBR IS NULL LEFT
																			   OUTER JOIN
																			   rdb.dbo.PHC_UIDS WITH(NOLOCK)
																			   ON PHC_UIDS.PAGE_CASE_UID = PA.act_uid LEFT
												OUTER JOIN
												NBS_SRTE.dbo.CODE_VALUE_GENERAL AS CVG WITH(NOLOCK)
												ON UPPER(CVG.CODE) = UPPER(rmeta.DATA_TYPE)
		WHERE CVG.CODE_SET_NM = 'NBS_DATA_TYPE' AND 
			  CODE IN( 'DATETIME', 'DATE' )
		ORDER BY ACT_UID, NBS_CASE_ANSWER_UID, rmeta.CODE_SET_GROUP_ID;

		SELECT @RowCount_no = @@ROWCOUNT;
		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_UNDER_CONDITION', 'RDB.S_INV_UNDER_CONDITION', 'START', @Proc_Step_no, @Proc_Step_Name, @RowCount_no );

		INSERT INTO rdb.dbo.ETL_DQ_LOG( EVENT_TYPE, EVENT_LOCAL_ID, EVENT_UID, DQ_ISSUE_CD, DQ_ISSUE_DESC_TXT, DQ_ISSUE_QUESTION_IDENTIFIER, DQ_ISSUE_ANSWER_TXT, DQ_ISSUE_RDB_LOCATION, JOB_BATCH_LOG_UID, DQ_ETL_PROCESS_TABLE, DQ_ETL_PROCESS_COLUMN, DQ_STATUS_TIME, DQ_ISSUE_SOURCE_LOCATION, DQ_ISSUE_SOURCE_QUESTION_LABEL )
		(
			SELECT 'INVESTIGATION', PUBLIC_HEALTH_CASE.LOCAL_ID, PUBLIC_HEALTH_CASE_UID, 'INVALID_DATE', 'BAD DATE: A poorly formatted date exists and requires update. Please correct the bad date so that it can be properly written to the reporting database during the next ETL run.', NBS_UI_METADATA.QUESTION_IDENTIFIER, ANSWER_TXT, NBS_UI_METADATA.DATA_LOCATION, @Batch_id, NBS_RDB_METADATA.rdb_table_nm, NBS_RDB_METADATA.RDB_COLUMN_NM, GETDATE(), NBS_UI_METADATA.DATA_LOCATION, QUESTION_LABEL
			FROM rdb.dbo.PHC_UIDS
				 INNER JOIN
				 NBS_ODSE..NBS_case_answer
				 ON NBS_case_answer.act_uid = PHC_UIDS.PAGE_CASE_UID
				 INNER JOIN
				 NBS_ODSE.DBO.PUBLIC_HEALTH_CASE
				 ON NBS_CASE_ANSWER.ACT_UID = PUBLIC_HEALTH_CASE.PUBLIC_HEALTH_CASE_UID
				 INNER JOIN
				 NBS_SRTE.DBO.CONDITION_CODE
				 ON CONDITION_CODE.CONDITION_CD = PUBLIC_HEALTH_CASE.CD
				 INNER JOIN
				 NBS_ODSE.DBO.NBS_UI_METADATA
				 ON NBS_CASE_ANSWER.NBS_QUESTION_UID = NBS_UI_METADATA.NBS_QUESTION_UID AND 
					CONDITION_CODE.INVESTIGATION_FORM_CD = NBS_UI_METADATA.INVESTIGATION_FORM_CD
				 INNER JOIN
				 NBS_ODSE.DBO.NBS_RDB_METADATA
				 ON NBS_RDB_METADATA.NBS_UI_METADATA_UID = NBS_UI_METADATA.NBS_UI_METADATA_UID
			WHERE DATA_TYPE IN( 'Date/Time', 'Date', 'DATETIME', 'DATE' ) AND 
				  (ISDATE(ANSWER_TXT) != 1) AND 
				  UPPER(NBS_UI_METADATA.DATA_LOCATION) = 'NBS_CASE_ANSWER.ANSWER_TXT' AND 
				  ANSWER_TXT IS NOT NULL AND 
				  NBS_RDB_METADATA.rdb_table_nm = 'D_INV_UNDER_CONDITION'
		);

		COMMIT TRANSACTION;

		BEGIN TRANSACTION;
		SET @Proc_Step_no = 32;
		SET @Proc_Step_Name = ' UPDATE TABLE date_data_INV_UNDER_CONDITION';
		UPDATE rdb.dbo.DATE_DATA_INV_UNDER_CONDITION
		  SET ANSWER_TXT1 = FORMAT(CAST([ANSWER_TXT] AS date), 'MM/dd/yy') + ' 00:00:00';
		--SET ANSWER_TXT=dhms(input(ANSWER_TXT1,MMDDYY10.),0,0,0); 
		--DROP ANSWER_TXT;
		--RENAME ANSWER_TXT=ANSWER_TXT1;   
		SELECT @RowCount_no = @@ROWCOUNT;
		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_UNDER_CONDITION', 'RDB.S_INV_UNDER_CONDITION', 'START', @Proc_Step_no, @Proc_Step_Name, @RowCount_no );

		COMMIT TRANSACTION;

		BEGIN TRANSACTION;
		SET @Proc_Step_no = 36;
		SET @Proc_Step_Name = ' CREATE TABLE PAGE_DATE_TABLE_INV_UNDER_CONDITION';
		IF OBJECT_ID('rdb.dbo.PAGE_DATE_TABLE_INV_UNDER_CONDITION', 'U') IS NOT NULL
		BEGIN
			DROP TABLE RDB.dbo.PAGE_DATE_TABLE_INV_UNDER_CONDITION;
		END;
		CREATE TABLE RDB.dbo.PAGE_DATE_TABLE_INV_UNDER_CONDITION
		( 
					 NBS_CASE_ANSWER_UID bigint, CODE_SET_GROUP_ID bigint, RDB_COLUMN_NM char(40), ANSWER_TXT1 date, PAGE_CASE_UID bigint, LAST_CHG_TIME date, RECORD_STATUS_CD char(40)
		);
 
		--IF PAGE_CASE_UID=. THEN PAGE_CASE_UID= 1;
		UPDATE rdb.dbo.DATE_DATA_INV_UNDER_CONDITION
		  SET PAGE_CASE_UID = 1
		WHERE PAGE_CASE_UID IS NULL;
		SELECT @RowCount_no = @@ROWCOUNT;
		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_UNDER_CONDITION', 'RDB.S_INV_UNDER_CONDITION', 'START', @Proc_Step_no, @Proc_Step_Name, @RowCount_no );

		COMMIT TRANSACTION;

		BEGIN TRANSACTION;
		SET @Proc_Step_no = 37;
		SET @Proc_Step_Name = ' UPDATE TABLE  PAGE_DATE_TABLE_INV_UNDER_CONDITION'; 
		--%DBLOAD (PAGE_DATE_TABLE, DATE_DATA); 
		INSERT INTO rdb.dbo.PAGE_DATE_TABLE_INV_UNDER_CONDITION( NBS_CASE_ANSWER_UID, CODE_SET_GROUP_ID, RDB_COLUMN_NM, ANSWER_TXT1, PAGE_CASE_UID, RECORD_STATUS_CD )
			   SELECT NBS_CASE_ANSWER_UID, CODE_SET_GROUP_ID, RDB_COLUMN_NM, CAST(ANSWER_TXT1 AS datetime), PAGE_CASE_UID, 
			   --	LAST_CHG_TIME , 
			   RECORD_STATUS_CD
			   FROM rdb.dbo.DATE_DATA_INV_UNDER_CONDITION;
		SELECT @RowCount_no = @@ROWCOUNT;
		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_UNDER_CONDITION', 'RDB.S_INV_UNDER_CONDITION', 'START', @Proc_Step_no, @Proc_Step_Name, @RowCount_no );

		COMMIT TRANSACTION;

		BEGIN TRANSACTION;
		SET @Proc_Step_no = 39;
		SET @Proc_Step_Name = ' UPDATE TABLE  PAGE_DATE_TABLE_INV_UNDER_CONDITION';
		IF OBJECT_ID('rdb.dbo.date_data_INV_UNDER_CONDITION_out', 'U') IS NOT NULL
		BEGIN
			DROP TABLE rdb.dbo.date_data_INV_UNDER_CONDITION_out;
		END;
		SET @columns = N'';
		SELECT @columns+=N', p.' + QUOTENAME(LTRIM(RTRIM([RDB_COLUMN_NM])))
		FROM
		(
			SELECT [RDB_COLUMN_NM]
			FROM [dbo].PAGE_DATE_TABLE_INV_UNDER_CONDITION AS p
			GROUP BY [RDB_COLUMN_NM]
		) AS x;
		SET @sql = N'
SELECT [PAGE_CASE_UID] as PAGE_CASE_UID_date, ' + STUFF(@columns, 1, 2, '') + ' into rdb.dbo.DATE_DATA_INV_UNDER_CONDITION_out ' + 'FROM (
SELECT [PAGE_CASE_UID], [answer_txt1] , [RDB_COLUMN_NM] 
 FROM rdb.[dbo].PAGE_DATE_TABLE_INV_UNDER_CONDITION
	group by [PAGE_CASE_UID], [answer_txt1] , [RDB_COLUMN_NM] 
		) AS j PIVOT (max(answer_txt1) FOR [RDB_COLUMN_NM] in 
	   (' + STUFF(REPLACE(@columns, ', p.[', ',['), 1, 1, '') + ')) AS p;';
		PRINT @sql;
		EXEC sp_executesql @sql;
		--select * from rdb.dbo.DATE_DATA_INV_UNDER_CONDITION_out;
		SELECT @RowCount_no = @@ROWCOUNT;
		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_UNDER_CONDITION', 'RDB.S_INV_UNDER_CONDITION', 'START', @Proc_Step_no, @Proc_Step_Name, @RowCount_no );

		COMMIT TRANSACTION;

		BEGIN TRANSACTION;
		SET @Proc_Step_no = 40;
		SET @Proc_Step_Name = ' UPDATE TABLE  RDB_UI_METADATA_INV_UNDER_CONDITION'; 
		--create table rdb_ui_metadata as 
		IF OBJECT_ID('rdb.dbo.RDB_UI_METADATA_INV_UNDER_CONDITION_TEMP', 'U') IS NOT NULL
		BEGIN
			DROP TABLE rdb.dbo.RDB_UI_METADATA_INV_UNDER_CONDITION_TEMP;
		END;

		SELECT DISTINCT 
			   NRDBM.RDB_COLUMN_NM, NUIM.NBS_QUESTION_UID, NUIM.CODE_SET_GROUP_ID, NUIM.INVESTIGATION_FORM_CD, CODE_SET_GROUP_ID AS CODE_SET_GROUP_ID1, QUESTION_GROUP_SEQ_NBR, DATA_TYPE
		INTO rdb.dbo.RDB_UI_METADATA_INV_UNDER_CONDITION_TEMP
		FROM NBS_ODSE.[dbo].NBS_RDB_METADATA AS NRDBM WITH(NOLOCK), NBS_ODSE.[dbo].NBS_UI_METADATA AS NUIM WITH(NOLOCK)
		WHERE NRDBM.NBS_UI_METADATA_UID = NUIM.NBS_UI_METADATA_UID AND 
			  NRDBM.RDB_TABLE_NM = 'D_INV_UNDER_CONDITION' AND 
			  nuim.QUESTION_GROUP_SEQ_NBR IS NULL AND 
			  nuim.DATA_TYPE IN( 'Numeric', 'NUMERIC' ) AND 
			  NUIM.nbs_question_uid NOT IN
		(
			SELECT nbs_question_uid
			FROM CODED_TABLE_SNTEMP_TRANS_A_INV_UNDER_CONDITION
		);

		IF OBJECT_ID('rdb.dbo.RDB_UI_METADATA_INV_UNDER_CONDITION', 'U') IS NOT NULL
		BEGIN
			DROP TABLE rdb.dbo.RDB_UI_METADATA_INV_UNDER_CONDITION;
		END;

		SELECT *
		INTO [RDB].[dbo].RDB_UI_METADATA_INV_UNDER_CONDITION
		FROM
		(
			SELECT *, ROW_NUMBER() OVER(PARTITION BY NBS_QUESTION_UID
			ORDER BY NBS_QUESTION_UID) AS rowid
			FROM [RDB].[dbo].RDB_UI_METADATA_INV_UNDER_CONDITION_TEMP
		) AS Der
		WHERE rowid = 1;
 
		--CREATE TABLE NUMERIC_BASE_DATA_INV_UNDER_CONDITION AS
		SELECT @RowCount_no = @@ROWCOUNT;
		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_UNDER_CONDITION', 'RDB.S_INV_UNDER_CONDITION', 'START', @Proc_Step_no, @Proc_Step_Name, @RowCount_no );

		COMMIT TRANSACTION;

		BEGIN TRANSACTION;
		SET @Proc_Step_no = 41;
		SET @Proc_Step_Name = ' CREATE TABLE  NUMERIC_BASE_DATA_INV_UNDER_CONDITION';
		IF OBJECT_ID('rdb.dbo.NUMERIC_BASE_DATA_INV_UNDER_CONDITION', 'U') IS NOT NULL
		BEGIN
			DROP TABLE NUMERIC_BASE_DATA_INV_UNDER_CONDITION;
		END;

		SELECT NBS_CASE_ANSWER_UID, rmeta.CODE_SET_GROUP_ID, RDB_COLUMN_NM, CAST(ANSWER_TXT AS varchar(2000)) AS ANSWER_TXT, ACT_UID AS PAGE_CASE_UID, PA.RECORD_STATUS_CD, rmeta.NBS_QUESTION_UID, LEN(RTRIM(ANSWER_TXT)) AS TXT_LEN, CAST(NULL AS [varchar](2000)) AS ANSWER_UNIT, CAST(NULL AS int) AS LENCODED, CAST(NULL AS [varchar](2000)) AS ANSWER_CODED, CAST(NULL AS [varchar](2000)) AS UNIT_VALUE1, CAST(NULL AS [varchar](30)) AS RDB_COLUMN_NM2
		INTO rdb.dbo.NUMERIC_BASE_DATA_INV_UNDER_CONDITION
		FROM rdb.dbo.RDB_UI_METADATA_INV_UNDER_CONDITION AS rmeta WITH(NOLOCK) LEFT
			 OUTER JOIN
			 NBS_ODSE.[dbo].NBS_CASE_ANSWER AS PA WITH(NOLOCK)
			 ON rmeta.nbs_question_uid = PA.nbs_question_uid AND 
				pa.ANSWER_GROUP_SEQ_NBR IS NULL LEFT
																			   OUTER JOIN
																			   rdb.dbo.PHC_UIDS
																			   ON PHC_UIDS.PAGE_CASE_UID = PA.act_uid
												INNER JOIN
												NBS_SRTE.dbo.CODE_VALUE_GENERAL AS CVG WITH(NOLOCK)
												ON UPPER(CVG.CODE) = UPPER(rmeta.DATA_TYPE)
		WHERE CVG.CODE_SET_NM = 'NBS_DATA_TYPE' AND 
			  CODE IN( 'Numeric', 'NUMERIC' )
		ORDER BY ACT_UID, NBS_CASE_ANSWER_UID, rmeta.CODE_SET_GROUP_ID;
		SELECT @RowCount_no = @@ROWCOUNT;
		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_UNDER_CONDITION', 'RDB.S_INV_UNDER_CONDITION', 'START', @Proc_Step_no, @Proc_Step_Name, @RowCount_no );

		COMMIT TRANSACTION;

		BEGIN TRANSACTION;
		SET @Proc_Step_no = 43;
		SET @Proc_Step_Name = ' UPDATE TABLE  NUMERIC_BASE_DATA_INV_UNDER_CONDITION'; 
		--update rdb.dbo.NUMERIC_BASE_DATA_INV_UNDER_CONDITION set TXT_LEN=LEN(RTRIM(ANSWER_TXT));
		UPDATE rdb.dbo.NUMERIC_BASE_DATA_INV_UNDER_CONDITION
		  SET ANSWER_UNIT = SUBSTRING(ANSWER_TXT, 1, ( CHARINDEX('^', ANSWER_TXT) - 1 ))
		WHERE CHARINDEX('^', ANSWER_TXT) > 0;
		UPDATE rdb.dbo.NUMERIC_BASE_DATA_INV_UNDER_CONDITION
		  SET LENCODED = LEN(RTRIM(ANSWER_UNIT))
		WHERE CHARINDEX('^', ANSWER_TXT) > 0;
		UPDATE rdb.dbo.NUMERIC_BASE_DATA_INV_UNDER_CONDITION
		  SET ANSWER_CODED = SUBSTRING(ANSWER_TXT, ( LENCODED + 2 ), TXT_LEN)
		WHERE CHARINDEX('^', ANSWER_TXT) > 0;
		UPDATE rdb.dbo.NUMERIC_BASE_DATA_INV_UNDER_CONDITION
		  SET UNIT_VALUE1 = REPLACE(ANSWER_UNIT, ',', '')
		WHERE CHARINDEX('^', ANSWER_TXT) > 0;
		UPDATE rdb.dbo.NUMERIC_BASE_DATA_INV_UNDER_CONDITION
		  SET RDB_COLUMN_NM2 = SUBSTRING(RTRIM(RDB_COLUMN_NM), 1, 25) + ' UNIT'
		WHERE LEN(RTRIM(ANSWER_CODED)) > 0;
		IF OBJECT_ID('rdb.dbo.NUMERIC_DATA_2_INV_UNDER_CONDITION', 'U') IS NOT NULL
		BEGIN
			DROP TABLE NUMERIC_DATA_2_INV_UNDER_CONDITION;
		END;

		SELECT *
		INTO rdb.dbo.NUMERIC_DATA_2_INV_UNDER_CONDITION
		FROM rdb.dbo.NUMERIC_BASE_DATA_INV_UNDER_CONDITION;
		UPDATE rdb.dbo.NUMERIC_DATA_2_INV_UNDER_CONDITION
		  SET RDB_COLUMN_NM = RDB_COLUMN_NM2
		WHERE LEN(RTRIM(RDB_COLUMN_NM2)) > 0;
		SELECT @RowCount_no = @@ROWCOUNT;
		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_UNDER_CONDITION', 'RDB.S_INV_UNDER_CONDITION', 'START', @Proc_Step_no, @Proc_Step_Name, @RowCount_no );

		COMMIT TRANSACTION;

		BEGIN TRANSACTION;
		SET @Proc_Step_no = 44;
		SET @Proc_Step_Name = ' CREATE TABLE  NUMERIC_DATA_MERGED_INV_UNDER_CONDITION';
		IF OBJECT_ID('rdb.dbo.NUMERIC_DATA_MERGED_INV_UNDER_CONDITION', 'U') IS NOT NULL
		BEGIN
			DROP TABLE rdb.dbo.NUMERIC_DATA_MERGED_INV_UNDER_CONDITION;
		END;

		SELECT COALESCE(nbd.NBS_CASE_ANSWER_UID, nd2.NBS_CASE_ANSWER_UID) AS NBS_CASE_ANSWER_UID, COALESCE(nbd.[RDB_COLUMN_NM2], nd2.[RDB_COLUMN_NM2]) AS [RDB_COLUMN_NM2], COALESCE(nbd.[CODE_SET_GROUP_ID], nd2.[CODE_SET_GROUP_ID]) AS [CODE_SET_GROUP_ID], COALESCE(nbd.[RDB_COLUMN_NM], nd2.[RDB_COLUMN_NM]) AS [RDB_COLUMN_NM], COALESCE(nbd.[ANSWER_TXT], nd2.[ANSWER_TXT]) AS [ANSWER_TXT], COALESCE(nbd.[PAGE_CASE_UID], nd2.[PAGE_CASE_UID]) AS [PAGE_CASE_UID], COALESCE(nbd.[RECORD_STATUS_CD], nd2.[RECORD_STATUS_CD]) AS [RECORD_STATUS_CD], COALESCE(nbd.[NBS_QUESTION_UID], nd2.[NBS_QUESTION_UID]) AS [NBS_QUESTION_UID], COALESCE(nbd.[TXT_LEN], nd2.[TXT_LEN]) AS [TXT_LEN], COALESCE(nbd.[ANSWER_UNIT], nd2.[ANSWER_UNIT]) AS [ANSWER_UNIT], COALESCE(nbd.[LENCODED], nd2.[LENCODED]) AS [LENCODED], COALESCE(nbd.[ANSWER_CODED], nd2.[ANSWER_CODED]) AS [ANSWER_CODED], COALESCE(nbd.[UNIT_VALUE1], nd2.[UNIT_VALUE1]) AS [UNIT_VALUE1]
		INTO rdb.dbo.NUMERIC_DATA_MERGED_INV_UNDER_CONDITION
		FROM [RDB].[dbo].NUMERIC_BASE_DATA_INV_UNDER_CONDITION AS nbd
			 FULL OUTER JOIN
			 [RDB].[dbo].NUMERIC_DATA_2_INV_UNDER_CONDITION AS nd2
			 ON nbd.NBS_CASE_ANSWER_UID = nd2.NBS_CASE_ANSWER_UID AND 
				nbd.[RDB_COLUMN_NM] = nd2.[RDB_COLUMN_NM];
		SELECT @RowCount_no = @@ROWCOUNT;
		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_UNDER_CONDITION', 'RDB.S_INV_UNDER_CONDITION', 'START', @Proc_Step_no, @Proc_Step_Name, @RowCount_no );

		COMMIT TRANSACTION;

		BEGIN TRANSACTION;
		SET @Proc_Step_no = 45;
		SET @Proc_Step_Name = ' CREATE TABLE  NUMERIC_DATA_TRANS_INV_UNDER_CONDITION'; 
		--CREATE TABLE 	NUMERIC_DATA_TRANS  AS 
		IF OBJECT_ID('rdb.dbo.NUMERIC_DATA_TRANS_INV_UNDER_CONDITION', 'U') IS NOT NULL
		BEGIN
			DROP TABLE rdb.dbo.NUMERIC_DATA_TRANS_INV_UNDER_CONDITION;
		END;

		SELECT PAGE_CASE_UID, NBS_QUESTION_UID, NBS_CASE_ANSWER_UID, ANSWER_UNIT, ANSWER_CODED, CVG.CODE_SET_NM, RDB_COLUMN_NM, ANSWER_TXT, CODE, CODE_SHORT_DESC_TXT AS UNIT, CAST(NULL AS [varchar](2000)) AS ANSWER_TXT_F
		INTO rdb.dbo.NUMERIC_DATA_TRANS_INV_UNDER_CONDITION
		FROM rdb.dbo.NUMERIC_DATA_MERGED_INV_UNDER_CONDITION AS CODED WITH(NOLOCK) LEFT
			 JOIN
			 NBS_SRTE.dbo.CODESET_GROUP_METADATA AS METADATA WITH(NOLOCK)
			 ON METADATA.CODE_SET_GROUP_ID = CODED.CODE_SET_GROUP_ID LEFT
																				   JOIN
																				   NBS_SRTE.dbo.CODE_VALUE_GENERAL AS CVG WITH(NOLOCK)
																				   ON CVG.CODE_SET_NM = METADATA.CODE_SET_NM
		WHERE CVG.CODE = CODED.ANSWER_CODED OR 
			  ANSWER_CODED IS NULL
		ORDER BY PAGE_CASE_UID;
		UPDATE rdb.dbo.NUMERIC_DATA_TRANS_INV_UNDER_CONDITION
		  SET PAGE_CASE_UID = COALESCE(PAGE_CASE_UID, 1), ANSWER_TXT_F = CASE
																		 WHEN COALESCE(RTRIM(UNIT), '') = '' THEN ANSWER_TXT
																		 WHEN CHARINDEX(' UNIT', RDB_COLUMN_NM) > 0 THEN UNIT
																		 ELSE ANSWER_UNIT
																		 END;

		SELECT @RowCount_no = @@ROWCOUNT;
		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_UNDER_CONDITION', 'RDB.S_INV_UNDER_CONDITION', 'START', @Proc_Step_no, @Proc_Step_Name, @RowCount_no );


		COMMIT TRANSACTION;

		BEGIN TRANSACTION;
		SET @Proc_Step_no = 48;
		SET @Proc_Step_Name = ' UPDATE TABLE  CODED_TABLE_SNTEMP_TRANS_A_INV_UNDER_CONDITION'; 
		--CREATE TABLE NUMERIC_DATA_TRANS1_INV_UNDER_CONDITION AS 
		IF OBJECT_ID('rdb.dbo.NUMERIC_DATA_TRANS1_INV_UNDER_CONDITION', 'U') IS NOT NULL
		BEGIN
			DROP TABLE rdb.dbo.NUMERIC_DATA_TRANS1_INV_UNDER_CONDITION;
		END;
		IF OBJECT_ID('rdb.dbo.CODED_TABLE_MERGED_INV_UNDER_CONDITION', 'U') IS NULL
		BEGIN
			CREATE TABLE [dbo].CODED_TABLE_MERGED_INV_UNDER_CONDITION
			( 
						 [RDB_COLUMN_NM] [varchar](30) NULL, [ANSWER_TXT] [varchar](2000) NULL
			)
			ON [PRIMARY];
		END;

		SELECT DISTINCT 
			   ndtis.PAGE_CASE_UID, ndtis.RDB_COLUMN_NM, ANSWER_UNIT, ANSWER_TXT_F AS ANSWER_TXT
		INTO rdb.dbo.NUMERIC_DATA_TRANS1_INV_UNDER_CONDITION
		FROM rdb.dbo.NUMERIC_DATA_TRANS_INV_UNDER_CONDITION AS ndtis LEFT
			 OUTER JOIN
			 rdb.dbo.CODED_TABLE_MERGED_INV_UNDER_CONDITION AS ctmis
			 ON ndtis.RDB_COLUMN_NM = ctmis.RDB_COLUMN_NM AND 
				ctmis.answer_txt IS NOT NULL AND 
				ctmis.RDB_COLUMN_NM IS NULL;


		COMMIT TRANSACTION;

		BEGIN TRANSACTION;
		WITH lst
			 AS (SELECT ndtis.rdb_column_nm,
							  CASE
							  WHEN ndtis.answer_txt IS NOT NULL THEN 1
							  ELSE 0
							  END AS Ans_null
				 FROM rdb.[dbo].[NUMERIC_DATA_TRANS1_INV_UNDER_CONDITION] AS ndtis LEFT
					  OUTER JOIN
					  rdb.dbo.CODED_TABLE_MERGED_INV_UNDER_CONDITION AS ctmis
					  ON ndtis.RDB_COLUMN_NM = ctmis.RDB_COLUMN_NM AND 
						 ctmis.answer_txt IS NOT NULL AND 
						 ctmis.RDB_COLUMN_NM IS NULL)
			 DELETE FROM rdb.dbo.CODED_TABLE_MERGED_INV_UNDER_CONDITION
			 WHERE RDB_COLUMN_NM IN
			 (
				 SELECT rdb_column_nm
				 FROM lst
				 WHERE ans_null != 0
			 );

		COMMIT TRANSACTION;

		BEGIN TRANSACTION;
		WITH lst
			 AS (SELECT rdb_column_nm,
						CASE
						WHEN answer_txt IS NOT NULL THEN 1
						ELSE 0
						END AS Ans_null
				 FROM rdb.[dbo].[NUMERIC_DATA_TRANS1_INV_UNDER_CONDITION]
				 WHERE RDB_COLUMN_NM IN
				 (
					 SELECT RDB_COLUMN_NM
					 FROM rdb.dbo.CODED_TABLE_MERGED_INV_UNDER_CONDITION
					 GROUP BY rdb_column_nm
				 )
				 GROUP BY rdb_column_nm,
						  CASE
						  WHEN answer_txt IS NOT NULL THEN 1
						  ELSE 0
						  END)
			 DELETE FROM rdb.[dbo].[NUMERIC_DATA_TRANS1_INV_UNDER_CONDITION]
			 WHERE rdb_column_nm IN
			 (
				 SELECT rdb_column_nm
				 FROM lst
				 WHERE ans_null = 0
				 EXCEPT
				 SELECT rdb_column_nm
				 FROM lst
				 WHERE ans_null = 1
			 );
		COMMIT TRANSACTION;

		BEGIN TRANSACTION;
		SET @Proc_Step_no = 49;
		SET @Proc_Step_Name = ' CREATE TABLE  CODED_DATA_INV_UNDER_CONDITION_out';
		IF OBJECT_ID('rdb.dbo.CODED_DATA_INV_UNDER_CONDITION_out', 'U') IS NOT NULL
		BEGIN
			DROP TABLE rdb.dbo.CODED_DATA_INV_UNDER_CONDITION_out;
		END;
		IF OBJECT_ID('rdb.dbo.CODED_TABLE_MERGED_INV_UNDER_CONDITION', 'U') IS NOT NULL
		BEGIN
			UPDATE rdb.[dbo].CODED_TABLE_MERGED_INV_UNDER_CONDITION
			  SET answer_desc11 = NULL
			WHERE answer_desc11 = '';
		END;

		IF OBJECT_ID('rdb.dbo.CODED_TABLE_MERGED_INV_UNDER_CONDITION', 'U') IS NOT NULL
		BEGIN
			UPDATE rdb.[dbo].CODED_TABLE_MERGED_INV_UNDER_CONDITION
			  SET answer_desc11 = ANSWER_VALUE
			WHERE ANSWER_OTH IS NOT NULL AND 
				  ANSWER_VALUE IS NOT NULL AND 
				  answer_desc11 IS NULL AND 
				  answer_oth IS NOT NULL;
		END;

		IF OBJECT_ID('rdb.dbo.CODED_TABLE_MERGED_INV_UNDER_CONDITION', 'U') IS NOT NULL
		BEGIN
			UPDATE rdb.[dbo].CODED_TABLE_MERGED_INV_UNDER_CONDITION
			  SET answer_desc11 = ANSWER_TXT
			WHERE ANSWER_OTH IS NULL AND 
				  ANSWER_TXT2 IS NOT NULL AND 
				  ( answer_desc11 IS NULL
				  ) AND 
				  answer_oth IS NULL AND 
				  LEN(ANSWER_TXT2) > 0;
		END;

		IF OBJECT_ID('rdb.dbo.CODED_TABLE_MERGED_INV_UNDER_CONDITION', 'U') IS NOT NULL
		BEGIN
			UPDATE rdb.[dbo].CODED_TABLE_MERGED_INV_UNDER_CONDITION
			  SET answer_desc11 = ANSWER_TXT
			WHERE ANSWER_OTH IS NULL AND 
				  ANSWER_TXT2 IS NOT NULL AND 
				  ( answer_desc11 IS NULL
				  ) AND 
				  answer_oth IS NULL AND 
				  LEN(ANSWER_TXT) > 0;
		END;



		IF OBJECT_ID('rdb.dbo.CODED_TABLE_MERGED_INV_UNDER_CONDITION', 'U') IS NOT NULL
		BEGIN
			UPDATE rdb.[dbo].CODED_TABLE_MERGED_INV_UNDER_CONDITION
			  SET answer_desc11 = ANSWER_VALUE
			WHERE ANSWER_OTH IS NULL AND 
				  ANSWER_VALUE IS NOT NULL AND 
				  answer_desc11 IS NULL AND 
				  answer_txt IS NOT NULL AND 
				  code = '';
		END;

		IF OBJECT_ID('rdb.dbo.CODED_TABLE_MERGED_INV_UNDER_CONDITION', 'U') IS NOT NULL
		BEGIN
			UPDATE rdb.[dbo].CODED_TABLE_MERGED_INV_UNDER_CONDITION
			  SET answer_desc11 = ANSWER_TXT
			WHERE answer_desc11 IS NULL AND 
				  ANSWER_OTH IS NULL AND 
				  ANSWER_TXT2 IS NULL AND 
				  answer_oth IS NULL AND 
				  ANSWER_TXT IS NOT NULL AND 
				  ANSWER_TXT <> ''
		END;

		SET @columns = N'';
		SELECT @columns+=N', p.' + QUOTENAME(LTRIM(RTRIM([RDB_COLUMN_NM])))
		FROM
		(
			SELECT [RDB_COLUMN_NM]
			FROM [dbo].CODED_TABLE_MERGED_INV_UNDER_CONDITION AS p
			GROUP BY [RDB_COLUMN_NM]
		) AS x;
		SET @sql = N'
SELECT [PAGE_CASE_UID] as PAGE_CASE_UID_coded, ' + STUFF(@columns, 1, 2, '') + ' into rdb.dbo.CODED_DATA_INV_UNDER_CONDITION_out ' + 'FROM (
SELECT [PAGE_CASE_UID], [ANSWER_DESC11] , [RDB_COLUMN_NM] 
 FROM rdb.[dbo].CODED_TABLE_MERGED_INV_UNDER_CONDITION
	group by [PAGE_CASE_UID], [ANSWER_DESC11] , [RDB_COLUMN_NM] 
		) AS j PIVOT (max(ANSWER_DESC11) FOR [RDB_COLUMN_NM] in 
	   (' + STUFF(REPLACE(@columns, ', p.[', ',['), 1, 1, '') + ')) AS p;';
		PRINT @sql;
		EXEC sp_executesql @sql;
		SELECT @RowCount_no = @@ROWCOUNT;
		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_UNDER_CONDITION', 'RDB.S_INV_UNDER_CONDITION', 'START', @Proc_Step_no, @Proc_Step_Name, @RowCount_no );

		COMMIT TRANSACTION;
		BEGIN TRANSACTION;
		SET @Proc_Step_no = 49;
		SET @Proc_Step_Name = ' LOG Invalid Numeric data INTO ETL_DQ_LOG';
	
		INSERT INTO rdb.dbo.ETL_DQ_LOG( EVENT_TYPE, EVENT_LOCAL_ID, EVENT_UID, DQ_ISSUE_CD, DQ_ISSUE_DESC_TXT, DQ_ISSUE_QUESTION_IDENTIFIER, DQ_ISSUE_ANSWER_TXT, DQ_ISSUE_RDB_LOCATION, JOB_BATCH_LOG_UID, DQ_ETL_PROCESS_TABLE, DQ_ETL_PROCESS_COLUMN, DQ_STATUS_TIME, DQ_ISSUE_SOURCE_LOCATION, DQ_ISSUE_SOURCE_QUESTION_LABEL )
		(
		SELECT DISTINCT 'INVESTIGATION', PUBLIC_HEALTH_CASE.LOCAL_ID, PUBLIC_HEALTH_CASE_UID, 
		'INVALID_NUMERIC_VALUE', 'BAD NUMERIC VALUE: A non-numeric value exists in a field expecting a numeric value and requires update. Please correct the bad numeric value so that it can be properly written to the reporting database during the next ETL run', 
		NBS_UI_METADATA.QUESTION_IDENTIFIER, ANSWER_TXT, NBS_UI_METADATA.DATA_LOCATION, @Batch_id, NBS_RDB_METADATA.rdb_table_nm, NBS_RDB_METADATA.RDB_COLUMN_NM, 
		GETDATE(), NBS_UI_METADATA.DATA_LOCATION, QUESTION_LABEL
					FROM rdb.dbo.NUMERIC_DATA_TRANS1_INV_UNDER_CONDITION
			 INNER JOIN
				 NBS_ODSE.DBO.PUBLIC_HEALTH_CASE
				 ON NUMERIC_DATA_TRANS1_INV_UNDER_CONDITION.page_case_uid= PUBLIC_HEALTH_CASE.PUBLIC_HEALTH_CASE_UID
				 INNER JOIN
				 NBS_SRTE.DBO.CONDITION_CODE
				 ON CONDITION_CODE.CONDITION_CD = PUBLIC_HEALTH_CASE.CD
				  INNER JOIN
				 NBS_ODSE.DBO.NBS_RDB_METADATA
				 ON NBS_RDB_METADATA.rdb_column_nm = NUMERIC_DATA_TRANS1_INV_UNDER_CONDITION.rdb_column_nm
				 INNER JOIN
				 NBS_ODSE.DBO.NBS_UI_METADATA
				 ON NBS_RDB_METADATA.NBS_UI_METADATA_UID = NBS_UI_METADATA.NBS_UI_METADATA_UID AND 
					CONDITION_CODE.INVESTIGATION_FORM_CD = NBS_UI_METADATA.INVESTIGATION_FORM_CD
			WHERE (isNumeric(ANSWER_TXT) != 1) AND 
				  ANSWER_TXT IS NOT NULL);
		
		SELECT @RowCount_no = @@ROWCOUNT;
		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_UNDER_CONDITION', 'RDB.S_INV_UNDER_CONDITION', 'START', @Proc_Step_no, @Proc_Step_Name, @RowCount_no );


		COMMIT TRANSACTION;
		BEGIN TRANSACTION;
		SET @Proc_Step_no = 50;
		SET @Proc_Step_Name = ' CREATE TABLE  NUMERIC_DATA_PIVOT_INV_UNDER_CONDITION';
		IF OBJECT_ID('rdb.dbo.NUMERIC_DATA_PIVOT_INV_UNDER_CONDITION', 'U') IS NOT NULL
		BEGIN
			DROP TABLE rdb.dbo.NUMERIC_DATA_PIVOT_INV_UNDER_CONDITION;
		END;
		SET @columns = N'';
		SELECT @columns+=N', p.' + QUOTENAME(LTRIM(RTRIM([RDB_COLUMN_NM])))
		FROM
		(
			SELECT [RDB_COLUMN_NM]
			FROM [dbo].NUMERIC_DATA_TRANS1_INV_UNDER_CONDITION AS p
			GROUP BY [RDB_COLUMN_NM]
		) AS x;
		SET @sql = N'
SELECT [PAGE_CASE_UID] as PAGE_CASE_UID_NUMERIC, ' + STUFF(@columns, 1, 2, '') + ' into rdb.dbo.NUMERIC_DATA_PIVOT_INV_UNDER_CONDITION ' + 'FROM (
SELECT [PAGE_CASE_UID], [answer_txt] , [RDB_COLUMN_NM] 
 FROM rdb.[dbo].NUMERIC_DATA_TRANS1_INV_UNDER_CONDITION
  WHERE (isNumeric(ANSWER_TXT) = 1) AND  ANSWER_TXT IS NOT NULL 
	group by [PAGE_CASE_UID], [answer_txt] , [RDB_COLUMN_NM] 
		) AS j PIVOT (max(answer_txt) FOR [RDB_COLUMN_NM] in 
	   (' + STUFF(REPLACE(@columns, ', p.[', ',['), 1, 1, '') + ')) AS p;';
		PRINT @sql;
		EXEC sp_executesql @sql;
		SELECT @RowCount_no = @@ROWCOUNT;
		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_UNDER_CONDITION', 'RDB.S_INV_UNDER_CONDITION', 'START', @Proc_Step_no, @Proc_Step_Name, @RowCount_no );


		COMMIT TRANSACTION;


		BEGIN TRANSACTION;
