			INTO rdb.dbo.NUMERIC_DATA_OUT_INV_UNDER_CONDITION
			FROM rdb.dbo.NUMERIC_DATA_PIVOT_INV_UNDER_CONDITION
			WHERE 
			---??? LEN(RTRIM(_LABEL_))>0    AND 
			PAGE_CASE_UID_NUMERIC > 0;
		END;
		---************************************************
		SELECT @RowCount_no = @@ROWCOUNT;
		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_UNDER_CONDITION', 'RDB.S_INV_UNDER_CONDITION', 'START', @Proc_Step_no, @Proc_Step_Name, @RowCount_no );

