		END;

		SELECT NBS_CASE_ANSWER_UID, rmeta.CODE_SET_GROUP_ID, RDB_COLUMN_NM, CAST(ANSWER_TXT AS varchar(2000)) AS ANSWER_TXT, ACT_UID AS 'PAGE_CASE_UID', PA.RECORD_STATUS_CD, rmeta.NBS_QUESTION_UID, MASK, CAST(NULL AS [varchar](2000)) AS ANSWER_TXT_CODE, CAST(NULL AS [varchar](2000)) AS ANSWER_VALUE, PHC_UIDS.INVESTIGATION_FORM_CD
		INTO rdb.dbo.CODED_TABLE_SNTEMP_INV_VACCINATION
		FROM rdb.dbo.RDB_UI_METADATA_INV_VACCINATION AS rmeta WITH(NOLOCK) LEFT
			 OUTER JOIN
			 NBS_ODSE.[dbo].NBS_CASE_ANSWER AS PA WITH(NOLOCK)
			 ON rmeta.nbs_question_uid = PA.nbs_question_uid AND 
				pa.ANSWER_GROUP_SEQ_NBR IS NULL LEFT
																		   OUTER JOIN
																		   PHC_UIDS
																		   ON PHC_UIDS.PAGE_CASE_UID = PA.act_uid
												INNER JOIN
												NBS_SRTE.dbo.CODE_VALUE_GENERAL AS CVG WITH(NOLOCK)
												ON UPPER(CVG.CODE) = UPPER(rmeta.DATA_TYPE)
		WHERE CVG.CODE_SET_NM = 'NBS_DATA_TYPE' AND 
			  UPPER(data_type) = 'NUMERIC'
		ORDER BY ACT_UID, NBS_CASE_ANSWER_UID, rmeta.CODE_SET_GROUP_ID;
		SELECT @RowCount_no = @@ROWCOUNT;
		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_VACCINATION', 'RDB.S_INV_VACCINATION', 'START', @Proc_Step_no, @Proc_Step_Name, @RowCount_no );

