		SET @Proc_Step_Name = ' UPDATE TABLE  CODED_TABLE_SNTEMP_TRANS_A_INV_VACCINATION';

		UPDATE RDB.dbo.CODED_TABLE_SNTEMP_TRANS_A_INV_VACCINATION
		  SET ANSWER_TXT = REPLACE(ANSWER_VALUE, ' ', '')
		WHERE LEN(mask) > 0;
		UPDATE RDB.dbo.CODED_TABLE_SNTEMP_TRANS_A_INV_VACCINATION
		  SET ANSWER_TXT = REPLACE(ANSWER_VALUE, ' ', '') + ' ' + REPLACE(ANSWER_TXT2, ' ', '')
		WHERE LEN(mask) = 0;
		SELECT @RowCount_no = -1;
		INSERT INTO rdb.[dbo].[job_flow_log]( batch_id, [Dataflow_Name], [package_Name], [Status_Type], [step_number], [step_name], [row_count] )
		VALUES( @Batch_id, 'INV_VACCINATION', 'RDB.S_INV_VACCINATION', 'START', @Proc_Step_no, @Proc_Step_Name, @RowCount_no );

		COMMIT TRANSACTION;

		BEGIN TRANSACTION;
		SET @Proc_Step_no = 21;
		SET @Proc_Step_Name = ' UPDATE TABLE  CODED_TABLE_SNTEMP_TRANS_CODE_INV_VACCINATION';
		IF OBJECT_ID('rdb.dbo.CODED_TABLE_SNTEMP_TRANS_CODE_INV_VACCINATION', 'U') IS NOT NULL
		BEGIN
